fn preview_compact_timing_enabled() -> bool {
    static ENABLED: OnceLock<bool> = OnceLock::new();
    *ENABLED.get_or_init(|| std::env::var_os("BOON_NATIVE_PREVIEW_COMPACT_TIMING").is_some())
}

fn preview_interaction_profiles() -> &'static Mutex<VecDeque<serde_json::Value>> {
    static PROFILES: OnceLock<Mutex<VecDeque<serde_json::Value>>> = OnceLock::new();
    PROFILES.get_or_init(|| Mutex::new(VecDeque::with_capacity(PREVIEW_INTERACTION_PROFILE_LIMIT)))
}

fn preview_profiling_enabled() -> bool {
    if preview_hot_path_profile_suppressed().load(Ordering::Relaxed) {
        return false;
    }
    if std::env::var_os("BOON_NATIVE_PREVIEW_PROFILE_HOT_PATH").is_some() {
        return true;
    }
    preview_hot_path_profile_enabled().load(Ordering::Relaxed)
}

fn preview_set_hot_path_profile_enabled(enabled: bool) {
    preview_hot_path_profile_enabled().store(enabled, Ordering::Relaxed);
}

fn preview_hot_path_profile_enabled() -> &'static AtomicBool {
    static ENABLED: AtomicBool = AtomicBool::new(false);
    &ENABLED
}

fn preview_set_hot_path_profile_suppressed(suppressed: bool) {
    preview_hot_path_profile_suppressed().store(suppressed, Ordering::Relaxed);
}

fn preview_hot_path_profile_suppressed() -> &'static AtomicBool {
    static SUPPRESSED: AtomicBool = AtomicBool::new(false);
    &SUPPRESSED
}

