#[derive(Clone, Copy)]
struct SyntaxStyle {
    color: &'static str,
    font_weight: Option<&'static str>,
    font_style: Option<&'static str>,
}

fn syntax_style_for_kind(kind: &str) -> SyntaxStyle {
    match kind {
        "comment" => SyntaxStyle {
            color: "#778899",
            font_weight: None,
            font_style: Some("italic"),
        },
        "keyword" => SyntaxStyle {
            color: "#D2691E",
            font_weight: Some("800"),
            font_style: Some("italic"),
        },
        "source-binding" => SyntaxStyle {
            color: "#6cb6ff",
            font_weight: None,
            font_style: None,
        },
        "tag" => SyntaxStyle {
            color: "#6df59a",
            font_weight: None,
            font_style: None,
        },
        "type" => SyntaxStyle {
            color: "#6f9cff",
            font_weight: None,
            font_style: None,
        },
        "variable" | "text-literal-interpolation" => SyntaxStyle {
            color: "#eeeeee",
            font_weight: None,
            font_style: None,
        },
        "function" => SyntaxStyle {
            color: "#fcbf49",
            font_weight: Some("600"),
            font_style: None,
        },
        "definition" => SyntaxStyle {
            color: "#ff6ec7",
            font_weight: Some("600"),
            font_style: Some("italic"),
        },
        "operator" => SyntaxStyle {
            color: "#ff9f43",
            font_weight: Some("600"),
            font_style: None,
        },
        "punctuation" | "module-slash" | "dot" | "pipe" | "text-literal-delimiter" => SyntaxStyle {
            color: "#D2691E",
            font_weight: Some("700"),
            font_style: None,
        },
        "string" | "text-literal-content" => SyntaxStyle {
            color: "#fff59e",
            font_weight: None,
            font_style: None,
        },
        "number" | "negative-sign" => SyntaxStyle {
            color: "#7ad1ff",
            font_weight: None,
            font_style: None,
        },
        "wildcard" => SyntaxStyle {
            color: "#D2691E",
            font_weight: None,
            font_style: None,
        },
        "chain-alt" => SyntaxStyle {
            color: "#bbbbbb",
            font_weight: None,
            font_style: None,
        },
        "invalid" => SyntaxStyle {
            color: "#ffffff",
            font_weight: None,
            font_style: None,
        },
        _ => SyntaxStyle {
            color: BOON_EDITOR_FOREGROUND,
            font_weight: None,
            font_style: None,
        },
    }
}

fn syntax_color_for_kind(kind: &str) -> &'static str {
    syntax_style_for_kind(kind).color
}

fn syntax_font_weight_for_kind(kind: &str) -> Option<&'static str> {
    syntax_style_for_kind(kind).font_weight
}

fn syntax_font_style_for_kind(kind: &str) -> Option<&'static str> {
    syntax_style_for_kind(kind).font_style
}

fn syntax_style_json(kind: &str) -> serde_json::Value {
    let style = syntax_style_for_kind(kind);
    json!({
        "color": style.color,
        "font_weight": style.font_weight,
        "font_style": style.font_style
    })
}

fn slice_chars(text: &str, start: usize, end: usize) -> String {
    text.chars()
        .skip(start)
        .take(end.saturating_sub(start))
        .collect()
}

fn matching_brace_byte(source: &str, open_brace: usize) -> Option<usize> {
    if source.as_bytes().get(open_brace) != Some(&b'{') {
        return None;
    }
    let mut depth = 0usize;
    let mut position = open_brace;
    while position < source.len() {
        let ch = source[position..].chars().next()?;
        if ch == '{' {
            depth += 1;
        } else if ch == '}' {
            depth = depth.saturating_sub(1);
            if depth == 0 {
                return Some(position);
            }
        }
        position += ch.len_utf8();
    }
    None
}

#[derive(Clone, Debug)]
struct PreviewTransport {
    connect: Option<String>,
}

impl PreviewTransport {
    fn new(connect: Option<String>) -> Self {
        Self { connect }
    }

    fn replace_source_project(
        &self,
        command: &str,
        selected_example_id: &str,
        payload: &SourceProjectPayload,
    ) -> serde_json::Value {
        let source_hash = payload.project_hash.clone();
        let Some(connect) = &self.connect else {
            return json!({
                "status": "not-bound",
                "kind": "ReplaceCode",
                "command": command,
                "command_id": payload.command_id,
                "source_revision": payload.source_revision,
                "transport_bound": false,
                "selected_example_id": selected_example_id,
                "source_path": payload.entrypoint_unit,
                "active_file": payload.active_file(),
                "source_hash": source_hash,
                "source_unit_count": payload.units.len(),
                "runtime_source_unit_count": payload.runtime_units().len(),
                "preview_receives_example_name": false
            });
        };
        let json_request = || {
            json!({
                "kind": "replace-source",
                "payload": payload,
                "dev_pid": std::process::id()
            })
        };
        let ack_result =
            send_preview_source_project_ipc_request(connect, "replace-source", payload).and_then(
                |ack| {
                    if source_project_binary_ack_needs_json_fallback(&ack) {
                        let mut fallback_ack = send_preview_ipc_request(connect, json_request())?;
                        fallback_ack["source_project_ipc_binary_fallback"] = json!(true);
                        fallback_ack["source_project_ipc_binary_fallback_reason"] =
                            json!("preview did not understand source_project_frame");
                        Ok(fallback_ack)
                    } else {
                        Ok(ack)
                    }
                },
            );
        match ack_result {
            Ok(ack) => {
                let hash_matches = ack.get("hash_matches").and_then(serde_json::Value::as_bool)
                    == Some(true)
                    || ack.get("project_hash").and_then(serde_json::Value::as_str)
                        == Some(payload.project_hash.as_str());
                let ack_status = ack
                    .get("status")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or("fail");
                let ack_pass = matches!(ack_status, "pass" | "queued");
                json!({
                    "status": if hash_matches && ack_pass { "pass" } else { "fail" },
                    "kind": "ReplaceCode",
                    "command": command,
                    "command_id": payload.command_id,
                    "source_revision": payload.source_revision,
                    "replace_source_protocol": true,
                    "transport_bound": true,
                    "selected_example_id": selected_example_id,
                    "source_path": payload.entrypoint_unit,
                    "active_file": payload.active_file(),
                    "source_hash": source_hash,
                    "source_unit_count": payload.units.len(),
                    "runtime_source_unit_count": payload.runtime_units().len(),
                    "ack": ack,
                    "preview_receives_example_name": false
                })
            }
            Err(error) => json!({
                "status": "fail",
                "kind": "ReplaceCode",
                "command": command,
                "command_id": payload.command_id,
                "source_revision": payload.source_revision,
                "transport_bound": true,
                "selected_example_id": selected_example_id,
                "source_path": payload.entrypoint_unit,
                "active_file": payload.active_file(),
                "source_hash": source_hash,
                "source_unit_count": payload.units.len(),
                "runtime_source_unit_count": payload.runtime_units().len(),
                "diagnostic": error.to_string(),
                "preview_receives_example_name": false
            }),
        }
    }

    fn runtime_summary(&self) -> serde_json::Value {
        let Some(connect) = &self.connect else {
            return json!({
                "status": "not-bound",
                "kind": "debug-query-result",
                "debug_query": "RuntimeSummary",
                "transport_bound": false
            });
        };
        match send_preview_ipc_request_with_timeouts(
            connect,
            json!({"kind": "runtime-summary"}),
            Duration::ZERO,
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
        ) {
            Ok(value) => value,
            Err(error) => json!({
                "status": "unavailable",
                "kind": "debug-query-result",
                "debug_query": "RuntimeSummary",
                "transport_bound": true,
                "diagnostic": error.to_string()
            }),
        }
    }

    fn runtime_value(
        &self,
        paths: &[String],
        source_sha256: &str,
        state_summary_hash: &str,
        max_list_items: usize,
    ) -> serde_json::Value {
        let Some(connect) = &self.connect else {
            return json!({
                "status": "not-bound",
                "kind": "runtime-value-result",
                "transport_bound": false,
                "full_state_mirroring_allowed": false,
                "full_state_mirroring_observed": false
            });
        };
        match send_preview_ipc_request_with_timeouts(
            connect,
            json!({
                "kind": "runtime-value",
                "paths": paths,
                "source_sha256": source_sha256,
                "state_summary_hash": state_summary_hash,
                "max_depth": DEV_TYPE_INSPECTOR_VALUE_MAX_DEPTH,
                "max_fields": DEV_TYPE_INSPECTOR_VALUE_MAX_FIELDS,
                "max_list_items": max_list_items
            }),
            Duration::ZERO,
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
        ) {
            Ok(value) => value,
            Err(error) => json!({
                "status": "unavailable",
                "kind": "runtime-value-result",
                "transport_bound": true,
                "diagnostic": error.to_string(),
                "full_state_mirroring_allowed": false,
                "full_state_mirroring_observed": false
            }),
        }
    }

    fn start_headed_scenario(
        &self,
        scenario_id: &str,
        selected_example_id: &str,
    ) -> serde_json::Value {
        let Some(connect) = &self.connect else {
            return json!({
                "status": "not-bound",
                "kind": "headed-scenario-start-ack",
                "transport_bound": false,
                "scenario_id": scenario_id,
                "selected_example_id": selected_example_id
            });
        };
        match send_preview_ipc_request_with_timeouts(
            connect,
            json!({
                "kind": "headed-scenario-start",
                "scenario_id": scenario_id,
                "selected_example_id": selected_example_id,
                "dev_pid": std::process::id()
            }),
            Duration::ZERO,
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
            Duration::from_millis(DEV_PREVIEW_SUMMARY_READ_TIMEOUT_MS),
        ) {
            Ok(value) => value,
            Err(error) => json!({
                "status": "unavailable",
                "kind": "headed-scenario-start-ack",
                "transport_bound": true,
                "scenario_id": scenario_id,
                "selected_example_id": selected_example_id,
                "diagnostic": error.to_string()
            }),
        }
    }
}

