fn document_eval_pipe_value(
    input: usize,
    op: &str,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let input = document_eval_expr_value(expressions.get(input)?, expressions, context)?;
    document_eval_pipe_value_from_input(input, op, args, expressions, context)
}

fn document_eval_expr_value_with_delimited_input(
    expr_id: usize,
    input_override: usize,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let expr = expressions.get(expr_id)?;
    match &expr.kind {
        AstExprKind::Pipe { input, op, args } => {
            let input = if matches!(
                expressions.get(*input).map(|expr| &expr.kind),
                Some(AstExprKind::Delimiter)
            ) {
                document_eval_expr_value(expressions.get(input_override)?, expressions, context)?
            } else if document_expr_depends_on_delimiter(*input, expressions) {
                document_eval_expr_value_with_delimited_input(
                    *input,
                    input_override,
                    expressions,
                    context,
                )?
            } else {
                document_eval_expr_value(expressions.get(*input)?, expressions, context)?
            };
            document_eval_pipe_value_from_input(input, op, args, expressions, context)
        }
        _ => document_eval_expr_value(expr, expressions, context),
    }
}

fn document_expr_depends_on_delimiter(expr_id: usize, expressions: &[AstExpr]) -> bool {
    match expressions.get(expr_id).map(|expr| &expr.kind) {
        Some(AstExprKind::Delimiter) => true,
        Some(AstExprKind::Pipe { input, args, .. }) => {
            document_expr_depends_on_delimiter(*input, expressions)
                || args
                    .iter()
                    .any(|arg| document_expr_depends_on_delimiter(arg.value, expressions))
        }
        Some(AstExprKind::When { input }) => {
            document_expr_depends_on_delimiter(*input, expressions)
        }
        Some(AstExprKind::Then { input, output }) => {
            document_expr_depends_on_delimiter(*input, expressions)
                || output
                    .is_some_and(|output| document_expr_depends_on_delimiter(output, expressions))
        }
        Some(AstExprKind::Infix { left, right, .. }) => {
            document_expr_depends_on_delimiter(*left, expressions)
                || document_expr_depends_on_delimiter(*right, expressions)
        }
        _ => false,
    }
}

fn document_eval_pipe_value_from_input(
    mut input: Value,
    op: &str,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    if matches!(
        op,
        "List/is_not_empty"
            | "List/count"
            | "List/retain"
            | "List/filter_field_equal"
            | "List/filter_field_not_equal"
            | "List/any"
            | "List/every"
            | "List/map"
    ) && let Some(todos) = input.as_object().and_then(|object| object.get("todos"))
    {
        input = todos.clone();
    }
    if let Some(field) = op.strip_prefix("Field/") {
        return input
            .as_object()
            .and_then(|object| object.get(field))
            .cloned();
    }
    match op {
        "Bool/not" => input.as_bool().map(|value| Value::Bool(!value)),
        "List/is_not_empty" => input.as_array().map(|items| Value::Bool(!items.is_empty())),
        "List/count" => input.as_array().map(|items| json!(items.len() as u64)),
        "List/retain" => document_eval_list_retain(input, args, expressions, context),
        "List/filter_field_equal" => {
            document_eval_list_filter_field(input, args, expressions, context, true)
        }
        "List/filter_field_not_equal" => {
            document_eval_list_filter_field(input, args, expressions, context, false)
        }
        "List/map" => document_eval_list_map(input, args, expressions, context),
        "List/any" => document_eval_list_quantifier(input, args, expressions, context, true),
        "List/every" => document_eval_list_quantifier(input, args, expressions, context, false),
        "Text/is_empty" => input.as_str().map(|text| Value::Bool(text.is_empty())),
        "Text/is_not_empty" => input.as_str().map(|text| Value::Bool(!text.is_empty())),
        "Text/trim" => input
            .as_str()
            .map(|text| Value::String(text.trim().to_owned())),
        "Text/concat" => input.as_str().map(|text| {
            let with = document_call_arg_text(args, "with", expressions, context)
                .or_else(|| document_call_arg_text(args, "value", expressions, context))
                .unwrap_or_default();
            let separator =
                document_call_arg_text(args, "separator", expressions, context).unwrap_or_default();
            Value::String(format!("{text}{separator}{with}"))
        }),
        "Text/to_uppercase" => input
            .as_str()
            .map(|text| Value::String(text.to_ascii_uppercase())),
        "Text/starts_with" => input.as_str().map(|text| {
            Value::Bool(
                document_call_arg_text(args, "prefix", expressions, context)
                    .is_some_and(|prefix| text.starts_with(&prefix)),
            )
        }),
        "Text/contains" => input.as_str().map(|text| {
            Value::Bool(
                document_call_arg_text(args, "needle", expressions, context)
                    .is_some_and(|needle| text.contains(&needle)),
            )
        }),
        "Text/substring" => input.as_str().map(|text| {
            let start = document_optional_arg_i64(args, "start", expressions, context)
                .unwrap_or(0)
                .max(0) as usize;
            let length = document_optional_arg_i64(args, "length", expressions, context)
                .unwrap_or(0)
                .max(0) as usize;
            Value::String(text.chars().skip(start).take(length).collect())
        }),
        "Text/length" => input
            .as_str()
            .map(|text| json!(text.chars().count() as i64)),
        "Text/to_number" => input
            .as_str()
            .map(|text| document_text_to_number_value(text, args, expressions, context)),
        "Text/all_chars_in" => input.as_str().map(|text| {
            Value::Bool(
                document_call_arg_text(args, "chars", expressions, context)
                    .is_some_and(|chars| document_text_all_chars_in(text, &chars)),
            )
        }),
        "Number/bit_width" => {
            json_i64(input).map(|value| json!(boon_runtime::number_bit_width(value)))
        }
        "Number/to_text" => json_i64(input).map(|value| {
            Value::String(document_number_to_text_value(
                value,
                args,
                expressions,
                context,
            ))
        }),
        "Number/to_codepoint_text" => json_i64(input).map(|value| {
            Value::String(document_number_to_codepoint_text_value(
                value,
                args,
                expressions,
                context,
            ))
        }),
        "Number/to_ascii_text" => json_i64(input).map(|value| {
            Value::String(document_number_to_ascii_text_value(
                value,
                args,
                expressions,
                context,
            ))
        }),
        _ => document_eval_pipe_function_call(op, input, args, expressions, context),
    }
}

fn document_eval_pipe_function_call(
    function_name: &str,
    input: Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let functions = context.functions?;
    let (resolved_name, function) = document_resolve_function(functions, function_name, context)?;
    if functions.contains_render_constructor(function) || context.eval_depth > 64 {
        return None;
    }
    let data_reads_before = document_context_snapshot_data_reads(context);
    let cache_key =
        document_eval_pipe_call_cache_key(&resolved_name, &input, args, expressions, context);
    if let Some(entry) = context
        .eval_cache
        .lock()
        .ok()
        .and_then(|cache| cache.get(&cache_key).cloned())
    {
        document_context_record_data_reads(context, entry.data_reads);
        return Some(entry.value);
    }
    let mut scoped = DocumentEvalContext {
        root: context.root,
        locals: context.locals.child(),
        local_origins: context.local_origins.child(),
        render_args: context.render_args.child(),
        passed: context.passed.clone(),
        source_binding_index: Arc::clone(&context.source_binding_index),
        runtime_source_paths: Arc::clone(&context.runtime_source_paths),
        source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
        runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
        data_binding_index: Arc::clone(&context.data_binding_index),
        data_reads: Arc::clone(&context.data_reads),
        data_binding_targets: Arc::clone(&context.data_binding_targets),
        structural_data_reads: Arc::clone(&context.structural_data_reads),
        source_override: context.source_override.clone(),
        functions: context.functions,
        eval_depth: context.eval_depth + 1,
        eval_cache: Arc::clone(&context.eval_cache),
    };
    document_apply_function_namespace(&mut scoped, function);
    let formals = match &function.kind {
        AstStatementKind::Function { args, .. } => args.as_slice(),
        _ => &[],
    };
    if let Some(first) = formals.first() {
        scoped.locals.insert(first.clone(), input);
    }
    for (index, arg) in args.iter().enumerate() {
        let Some(name) = arg
            .name
            .as_deref()
            .or_else(|| formals.get(index.saturating_add(1)).map(String::as_str))
        else {
            continue;
        };
        let value = expressions
            .get(arg.value)
            .and_then(|expr| document_eval_expr_value(expr, expressions, context))
            .or_else(|| {
                expressions
                    .get(arg.value)
                    .and_then(|expr| document_expr_value(expr, expressions))
                    .map(Value::String)
            });
        if let Some(value) = value {
            if name == "PASS" {
                scoped.passed = Some(value);
            } else {
                scoped.locals.insert(name.to_owned(), value);
            }
        }
    }
    let value = document_eval_statement_sequence(&function.children, expressions, &scoped)?;
    let data_reads = document_context_new_data_reads_since(context, &data_reads_before);
    if let Ok(mut cache) = context.eval_cache.lock() {
        if cache.len() > 4096 {
            cache.clear();
        }
        cache.insert(
            cache_key,
            DocumentEvalCacheEntry {
                value: value.clone(),
                data_reads,
            },
        );
    }
    Some(value)
}

fn document_eval_pipe_call_cache_key(
    function_name: &str,
    input: &Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> DocumentEvalCacheKey {
    let arg_values = args
        .iter()
        .map(|arg| {
            let name = arg.name.as_deref().unwrap_or("");
            let value = expressions
                .get(arg.value)
                .and_then(|expr| document_eval_expr_value(expr, expressions, context))
                .or_else(|| {
                    expressions
                        .get(arg.value)
                        .and_then(|expr| document_expr_value(expr, expressions).map(Value::String))
                })
                .unwrap_or(Value::Null);
            (
                name.to_owned(),
                DocumentEvalCacheValueKey::from_json(&value),
            )
        })
        .collect::<Vec<_>>();
    DocumentEvalCacheKey::Pipe {
        function_name: function_name.to_owned(),
        input: DocumentEvalCacheValueKey::from_json(input),
        args: arg_values,
        passed: context
            .passed
            .as_ref()
            .map(DocumentEvalCacheValueKey::from_json),
    }
}

fn document_eval_function_call(
    function_name: &str,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let functions = context.functions?;
    let (resolved_name, function) = document_resolve_function(functions, function_name, context)?;
    if functions.contains_render_constructor(function) {
        return None;
    }
    if context.eval_depth > 64 {
        return None;
    }
    let data_reads_before = document_context_snapshot_data_reads(context);
    let cache_key = document_eval_call_cache_key(&resolved_name, args, expressions, context);
    if let Some(entry) = context
        .eval_cache
        .lock()
        .ok()
        .and_then(|cache| cache.get(&cache_key).cloned())
    {
        document_context_record_data_reads(context, entry.data_reads);
        return Some(entry.value);
    }
    let mut scoped = document_function_args_context(function, args, &[], expressions, context);
    scoped.eval_depth = context.eval_depth + 1;
    let value = document_eval_statement_sequence(&function.children, expressions, &scoped)?;
    let data_reads = document_context_new_data_reads_since(context, &data_reads_before);
    if let Ok(mut cache) = context.eval_cache.lock() {
        if cache.len() > 4096 {
            cache.clear();
        }
        cache.insert(
            cache_key,
            DocumentEvalCacheEntry {
                value: value.clone(),
                data_reads,
            },
        );
    }
    Some(value)
}

fn document_eval_call_cache_key(
    function_name: &str,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> DocumentEvalCacheKey {
    let arg_values = args
        .iter()
        .map(|arg| {
            let name = arg.name.as_deref().unwrap_or("");
            let value = expressions
                .get(arg.value)
                .and_then(|expr| document_eval_expr_value(expr, expressions, context))
                .or_else(|| {
                    expressions
                        .get(arg.value)
                        .and_then(|expr| document_expr_value(expr, expressions).map(Value::String))
                })
                .unwrap_or(Value::Null);
            (
                name.to_owned(),
                DocumentEvalCacheValueKey::from_json(&value),
            )
        })
        .collect::<Vec<_>>();
    DocumentEvalCacheKey::Call {
        function_name: function_name.to_owned(),
        args: arg_values,
        passed: context
            .passed
            .as_ref()
            .map(DocumentEvalCacheValueKey::from_json),
    }
}

fn document_function_contains_render_constructor(
    function: &AstStatement,
    expressions: &[AstExpr],
) -> bool {
    function
        .children
        .iter()
        .any(|child| document_statement_contains_render_constructor(child, expressions))
}

fn document_statement_contains_render_constructor(
    statement: &AstStatement,
    expressions: &[AstExpr],
) -> bool {
    canonical_element_function(statement, expressions).is_some()
        || statement
            .expr
            .and_then(|expr_id| expressions.get(expr_id))
            .is_some_and(|expr| match &expr.kind {
                AstExprKind::Call { function, .. } | AstExprKind::Pipe { op: function, .. } => {
                    boon_typecheck::is_registered_element_constructor(function)
                        || matches!(function.as_str(), "Scene/new" | "Document/new")
                }
                _ => false,
            })
        || statement
            .children
            .iter()
            .any(|child| document_statement_contains_render_constructor(child, expressions))
}

fn document_expr_may_render(
    expr_id: usize,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> bool {
    let Some(expr) = expressions.get(expr_id) else {
        return false;
    };
    match &expr.kind {
        AstExprKind::Call { function, .. } => {
            boon_typecheck::is_registered_element_constructor(function)
                || context
                    .functions
                    .and_then(|functions| {
                        document_resolve_function(functions, function, context)
                            .map(|(_, function)| function)
                    })
                    .is_some_and(|function| {
                        context.functions.is_some_and(|functions| {
                            functions.contains_render_constructor(function)
                        })
                    })
        }
        AstExprKind::Pipe { input, op, args } => {
            matches!(op.as_str(), "SOURCE" | "WHEN" | "WHILE")
                || boon_typecheck::is_registered_element_constructor(op)
                || context
                    .functions
                    .and_then(|functions| {
                        document_resolve_function(functions, op, context)
                            .map(|(_, function)| function)
                    })
                    .is_some_and(|function| {
                        context.functions.is_some_and(|functions| {
                            functions.contains_render_constructor(function)
                        })
                    })
                || document_expr_may_render(*input, expressions, context)
                || args
                    .iter()
                    .any(|arg| document_expr_may_render(arg.value, expressions, context))
        }
        AstExprKind::When { .. } | AstExprKind::ListLiteral { .. } => true,
        AstExprKind::Identifier(name) => context.render_args.contains_key(name),
        _ => false,
    }
}

fn document_eval_statement_sequence(
    statements: &[AstStatement],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let mut scoped = DocumentEvalContext {
        root: context.root,
        locals: context.locals.child(),
        local_origins: context.local_origins.child(),
        render_args: context.render_args.child(),
        passed: context.passed.clone(),
        source_binding_index: Arc::clone(&context.source_binding_index),
        runtime_source_paths: Arc::clone(&context.runtime_source_paths),
        source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
        runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
        data_binding_index: Arc::clone(&context.data_binding_index),
        data_reads: Arc::clone(&context.data_reads),
        data_binding_targets: Arc::clone(&context.data_binding_targets),
        structural_data_reads: Arc::clone(&context.structural_data_reads),
        source_override: context.source_override.clone(),
        functions: context.functions,
        eval_depth: context.eval_depth,
        eval_cache: Arc::clone(&context.eval_cache),
    };
    let mut last = None;
    let mut field_object = serde_json::Map::new();
    let mut saw_non_field = false;
    for statement in statements {
        if let Some(name) = document_field_name(statement) {
            if let Some(value) = document_eval_statement_value(statement, expressions, &scoped) {
                scoped.locals.insert(name.clone(), value.clone());
                field_object.insert(name, value.clone());
                last = Some(value);
            }
        } else if is_semantic_block_statement(statement, expressions) {
            saw_non_field = true;
            last =
                document_eval_block_statement_sequence(&statement.children, expressions, &scoped);
        } else if let Some(value) = document_eval_statement_value(statement, expressions, &scoped) {
            if let Value::Object(object) = &value {
                field_object.extend(object.clone());
                last = Some(Value::Object(field_object.clone()));
                continue;
            }
            saw_non_field = true;
            last = Some(value);
        }
    }
    if !saw_non_field && !field_object.is_empty() {
        return Some(Value::Object(field_object));
    }
    last
}

fn document_eval_block_statement_sequence(
    statements: &[AstStatement],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let mut scoped = DocumentEvalContext {
        root: context.root,
        locals: context.locals.child(),
        local_origins: context.local_origins.child(),
        render_args: context.render_args.child(),
        passed: context.passed.clone(),
        source_binding_index: Arc::clone(&context.source_binding_index),
        runtime_source_paths: Arc::clone(&context.runtime_source_paths),
        source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
        runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
        data_binding_index: Arc::clone(&context.data_binding_index),
        data_reads: Arc::clone(&context.data_reads),
        data_binding_targets: Arc::clone(&context.data_binding_targets),
        structural_data_reads: Arc::clone(&context.structural_data_reads),
        source_override: context.source_override.clone(),
        functions: context.functions,
        eval_depth: context.eval_depth,
        eval_cache: Arc::clone(&context.eval_cache),
    };
    let mut last = None;
    let mut field_object = serde_json::Map::new();
    let mut saw_non_field = false;
    for statement in statements {
        if let Some(name) = document_field_name(statement) {
            if let Some(value) = document_eval_statement_value(statement, expressions, &scoped) {
                scoped.locals.insert(name.clone(), value.clone());
                field_object.insert(name, value.clone());
                last = Some(value);
            }
        } else if is_semantic_block_statement(statement, expressions) {
            saw_non_field = true;
            last =
                document_eval_block_statement_sequence(&statement.children, expressions, &scoped);
        } else if let Some(value) = document_eval_statement_value(statement, expressions, &scoped) {
            saw_non_field = true;
            last = Some(value);
        }
    }
    if !saw_non_field && !field_object.is_empty() {
        return Some(Value::Object(field_object));
    }
    last
}

fn document_eval_statement_value(
    statement: &AstStatement,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    if let Some(expr_id) = statement.expr {
        let expr = expressions.get(expr_id)?;
        if let Some(resolved) =
            document_eval_chained_statement_value(statement, expressions, context)
        {
            return Some(resolved);
        }
        if let AstExprKind::ListLiteral { items, .. } = &expr.kind
            && items.is_empty()
            && !statement.children.is_empty()
        {
            return document_eval_list_literal_or_record_statement_children(
                &statement.children,
                expressions,
                context,
            );
        }
        if let Some(input) = document_when_input_expr_id(expr) {
            return document_eval_while_expr_value(
                input,
                statement.children.as_slice(),
                expressions,
                context,
            );
        }
        if statement_has_match_arm_children(statement, expressions) {
            let selector = document_eval_expr_value(expr, expressions, context)?;
            return document_eval_while_selector_value(
                selector,
                statement.children.as_slice(),
                expressions,
                context,
            );
        }
        return document_eval_expr_value(expr, expressions, context)
            .or_else(|| document_expr_value(expr, expressions).map(Value::String));
    }
    if is_semantic_block_statement(statement, expressions) {
        return document_eval_block_statement_sequence(&statement.children, expressions, context);
    }
    document_eval_statement_sequence(&statement.children, expressions, context)
}

fn document_eval_latest_statement_value(
    statement: &AstStatement,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let mut selected = None;
    for candidate in &statement.children {
        let value = document_eval_latest_candidate_value(candidate, expressions, context);
        if value.is_some() {
            selected = value;
        }
    }
    selected
}

fn document_eval_latest_candidate_value(
    statement: &AstStatement,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let Some(expr_id) = statement.expr else {
        return document_eval_statement_sequence(&statement.children, expressions, context);
    };
    let expr = expressions.get(expr_id)?;
    if let AstExprKind::Then { input, output } = &expr.kind {
        if !document_then_input_is_active(*input, expressions, context) {
            return None;
        }
        if let Some(output) = output {
            let output_expr = expressions.get(*output)?;
            if let Some(input) = document_when_input_expr_id(output_expr)
                && !statement.children.is_empty()
            {
                return document_eval_while_expr_value(
                    input,
                    statement.children.as_slice(),
                    expressions,
                    context,
                );
            }
            if let AstExprKind::ListLiteral { items, .. } = &output_expr.kind
                && items.is_empty()
                && !statement.children.is_empty()
            {
                return document_eval_list_literal_or_record_statement_children(
                    statement.children.as_slice(),
                    expressions,
                    context,
                );
            }
            return document_eval_expr_value(output_expr, expressions, context)
                .or_else(|| document_expr_value(output_expr, expressions).map(Value::String));
        }
        return document_eval_statement_sequence(&statement.children, expressions, context)
            .or_else(|| document_eval_expr_value(expressions.get(*input)?, expressions, context));
    }
    document_eval_statement_value(statement, expressions, context)
}

fn document_then_input_is_active(
    input: usize,
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> bool {
    let Some(value) = expressions
        .get(input)
        .and_then(|expr| document_eval_expr_value(expr, expressions, context))
    else {
        return false;
    };
    match value {
        Value::Null => false,
        Value::Bool(value) => value,
        Value::Number(_) => true,
        Value::String(value) => !value.is_empty(),
        Value::Array(values) => !values.is_empty(),
        Value::Object(object) => !object.is_empty(),
    }
}

fn is_semantic_block_statement(statement: &AstStatement, expressions: &[AstExpr]) -> bool {
    matches!(statement.kind, AstStatementKind::Block)
        && statement
            .expr
            .and_then(|expr_id| expressions.get(expr_id))
            .is_some_and(
                |expr| matches!(&expr.kind, AstExprKind::Identifier(value) if value == "BLOCK"),
            )
}

fn document_eval_list_literal_or_record_statement_children(
    children: &[AstStatement],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    if children
        .iter()
        .any(|child| document_field_name(child).is_some())
    {
        return document_eval_statement_sequence(children, expressions, context);
    }
    let values = children
        .iter()
        .filter_map(|child| document_eval_statement_value(child, expressions, context))
        .collect::<Vec<_>>();
    Some(Value::Array(values))
}

fn statement_has_match_arm_children(statement: &AstStatement, expressions: &[AstExpr]) -> bool {
    statement.children.iter().any(|child| {
        child
            .expr
            .and_then(|expr_id| expressions.get(expr_id))
            .is_some_and(|expr| matches!(expr.kind, AstExprKind::MatchArm { .. }))
    })
}

fn document_eval_list_retain(
    input: Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    document_eval_list_retain_with_statement_children(input, args, &[], expressions, context)
}

fn document_eval_list_retain_with_statement_children(
    input: Value,
    args: &[AstCallArg],
    statement_children: &[AstStatement],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let items = input.as_array()?;
    let item_name = list_item_arg_name(args, expressions)
        .or_else(|| {
            statement_children.iter().find_map(|child| {
                let AstExprKind::Identifier(name) = &expressions.get(child.expr?)?.kind else {
                    return None;
                };
                Some(name.as_str())
            })
        })
        .unwrap_or("item");
    let predicate_arg = args.iter().find(|arg| arg.name.as_deref() == Some("if"));
    let predicate_statement = statement_children.iter().find(|child| {
        document_field_name(child).as_deref() == Some("if")
            || child
                .expr
                .and_then(|expr_id| expressions.get(expr_id))
                .and_then(document_when_input_expr_id)
                .is_some()
    });
    let predicate_expr_id = predicate_arg
        .map(|arg| arg.value)
        .or_else(|| predicate_statement.and_then(|statement| statement.expr))?;
    let predicate_arms = predicate_statement
        .map(|child| child.children.as_slice())
        .unwrap_or(&[]);
    let mut retained = Vec::new();
    for item in items {
        let mut scoped = DocumentEvalContext {
            root: context.root,
            locals: context.locals.child(),
            local_origins: context.local_origins.child(),
            render_args: context.render_args.child(),
            passed: context.passed.clone(),
            source_binding_index: Arc::clone(&context.source_binding_index),
            runtime_source_paths: Arc::clone(&context.runtime_source_paths),
            source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
            runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
            data_binding_index: Arc::clone(&context.data_binding_index),
            data_reads: Arc::clone(&context.data_reads),
            data_binding_targets: Arc::clone(&context.data_binding_targets),
            structural_data_reads: Arc::clone(&context.structural_data_reads),
            source_override: context.source_override.clone(),
            functions: context.functions,
            eval_depth: context.eval_depth,
            eval_cache: Arc::clone(&context.eval_cache),
        };
        scoped.locals.insert(item_name.to_owned(), item.clone());
        let pass = expressions
            .get(predicate_expr_id)
            .and_then(|expr| {
                document_when_input_expr_id(expr)
                    .filter(|_| !predicate_arms.is_empty())
                    .and_then(|input| {
                        document_eval_while_expr_value(input, predicate_arms, expressions, &scoped)
                    })
                    .or_else(|| document_eval_expr_value(expr, expressions, &scoped))
            })
            .and_then(|value| value.as_bool())
            .unwrap_or(false);
        if pass {
            retained.push(item.clone());
        }
    }
    Some(Value::Array(retained))
}

fn document_eval_list_filter_field(
    input: Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
    equal: bool,
) -> Option<Value> {
    let field = document_call_arg_text(args, "field", expressions, context)?;
    let expected = document_call_arg_text(args, "value", expressions, context)?;
    let mut filtered = Vec::new();
    for item in input.as_array()? {
        let actual = item
            .as_object()
            .and_then(|object| object.get(&field))
            .map(json_value_to_document_text)
            .unwrap_or_default();
        if (actual == expected) == equal {
            filtered.push(item.clone());
        }
    }
    Some(Value::Array(filtered))
}

fn document_eval_list_map(
    input: Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
) -> Option<Value> {
    let items = input.as_array()?;
    let item_name = list_item_arg_name(args, expressions).unwrap_or("item");
    let map_arg = args
        .iter()
        .find(|arg| arg.name.as_deref() == Some("new"))
        .or_else(|| args.iter().find(|arg| arg.name.is_some()))?;
    let mut mapped = Vec::with_capacity(items.len());
    for item in items {
        let mut scoped = DocumentEvalContext {
            root: context.root,
            locals: context.locals.child(),
            local_origins: context.local_origins.child(),
            render_args: context.render_args.child(),
            passed: context.passed.clone(),
            source_binding_index: Arc::clone(&context.source_binding_index),
            runtime_source_paths: Arc::clone(&context.runtime_source_paths),
            source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
            runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
            data_binding_index: Arc::clone(&context.data_binding_index),
            data_reads: Arc::clone(&context.data_reads),
            data_binding_targets: Arc::clone(&context.data_binding_targets),
            structural_data_reads: Arc::clone(&context.structural_data_reads),
            source_override: context.source_override.clone(),
            functions: context.functions,
            eval_depth: context.eval_depth,
            eval_cache: Arc::clone(&context.eval_cache),
        };
        scoped.locals.insert(item_name.to_owned(), item.clone());
        let value = expressions
            .get(map_arg.value)
            .and_then(|expr| document_eval_expr_value(expr, expressions, &scoped))
            .or_else(|| {
                expressions
                    .get(map_arg.value)
                    .and_then(|expr| document_expr_value(expr, expressions).map(Value::String))
            })
            .unwrap_or(Value::Null);
        mapped.push(value);
    }
    Some(Value::Array(mapped))
}

fn document_eval_list_quantifier(
    input: Value,
    args: &[AstCallArg],
    expressions: &[AstExpr],
    context: &DocumentEvalContext<'_>,
    any: bool,
) -> Option<Value> {
    let items = input.as_array()?;
    let item_name = list_item_arg_name(args, expressions).unwrap_or("item");
    let predicate = args.iter().find(|arg| arg.name.as_deref() == Some("if"))?;
    let mut matched = false;
    for item in items {
        let mut scoped = DocumentEvalContext {
            root: context.root,
            locals: context.locals.child(),
            local_origins: context.local_origins.child(),
            render_args: context.render_args.child(),
            passed: context.passed.clone(),
            source_binding_index: Arc::clone(&context.source_binding_index),
            runtime_source_paths: Arc::clone(&context.runtime_source_paths),
            source_address_lookup_fields: Arc::clone(&context.source_address_lookup_fields),
            runtime_row_scope_by_list: Arc::clone(&context.runtime_row_scope_by_list),
            data_binding_index: Arc::clone(&context.data_binding_index),
            data_reads: Arc::clone(&context.data_reads),
            data_binding_targets: Arc::clone(&context.data_binding_targets),
            structural_data_reads: Arc::clone(&context.structural_data_reads),
            source_override: context.source_override.clone(),
            functions: context.functions,
            eval_depth: context.eval_depth,
            eval_cache: Arc::clone(&context.eval_cache),
        };
        scoped.locals.insert(item_name.to_owned(), item.clone());
        let pass = expressions
            .get(predicate.value)
            .and_then(|expr| document_eval_expr_value(expr, expressions, &scoped))
            .and_then(|value| value.as_bool())
            .unwrap_or(false);
        if any && pass {
            return Some(Value::Bool(true));
        }
        if !any && !pass {
            return Some(Value::Bool(false));
        }
        matched |= pass;
    }
    Some(Value::Bool(if any { matched } else { true }))
}

fn list_item_arg_name<'a>(args: &'a [AstCallArg], expressions: &'a [AstExpr]) -> Option<&'a str> {
    args.iter().find(|arg| arg.name.is_none()).and_then(|arg| {
        match &expressions.get(arg.value)?.kind {
            AstExprKind::Identifier(name) => Some(name.as_str()),
            _ => None,
        }
    })
}

fn document_eval_infix(left: &Value, op: &str, right: &Value) -> Option<Value> {
    let result = match op {
        "+" => return document_eval_number_infix(left, right, |left, right| Some(left + right)),
        "-" => return document_eval_number_infix(left, right, |left, right| Some(left - right)),
        "*" => return document_eval_number_infix(left, right, |left, right| Some(left * right)),
        "/" => {
            return document_eval_number_infix(left, right, |left, right| {
                (right != 0.0).then_some(left / right)
            });
        }
        "%" => {
            return document_eval_number_infix(left, right, |left, right| {
                (right != 0.0).then_some(left % right)
            });
        }
        "==" => json_values_equal(left, right),
        "!=" => !json_values_equal(left, right),
        ">" => json_values_cmp(left, right).is_some_and(|ordering| ordering.is_gt()),
        "<" => json_values_cmp(left, right).is_some_and(|ordering| ordering.is_lt()),
        ">=" => json_values_cmp(left, right).is_some_and(|ordering| {
            matches!(
                ordering,
                std::cmp::Ordering::Greater | std::cmp::Ordering::Equal
            )
        }),
        "<=" => json_values_cmp(left, right).is_some_and(|ordering| {
            matches!(
                ordering,
                std::cmp::Ordering::Less | std::cmp::Ordering::Equal
            )
        }),
        _ => return None,
    };
    Some(Value::Bool(result))
}

fn document_eval_number_infix(
    left: &Value,
    right: &Value,
    op: impl FnOnce(f64, f64) -> Option<f64>,
) -> Option<Value> {
    let left = left.as_f64()?;
    let right = right.as_f64()?;
    op(left, right).map(|value| json!(value))
}

fn json_values_equal(left: &Value, right: &Value) -> bool {
    match (left, right) {
        (Value::String(left), Value::String(right)) => left == right,
        (Value::Bool(left), Value::Bool(right)) => left == right,
        (Value::Number(left), Value::Number(right)) => left.as_f64() == right.as_f64(),
        _ => left == right,
    }
}

fn json_values_cmp(left: &Value, right: &Value) -> Option<std::cmp::Ordering> {
    match (left, right) {
        (Value::Number(left), Value::Number(right)) => left.as_f64()?.partial_cmp(&right.as_f64()?),
        (Value::String(left), Value::String(right)) => Some(left.cmp(right)),
        _ => None,
    }
}

fn document_resolved_text(raw: &str, context: &DocumentEvalContext<'_>) -> String {
    if !raw.starts_with('$') {
        return raw.to_owned();
    }
    document_resolved_value(raw, context)
        .map(json_value_to_document_text)
        .unwrap_or_else(|| raw.to_owned())
}

fn document_resolved_bool(raw: &str, context: &DocumentEvalContext<'_>) -> Option<bool> {
    match document_resolved_value(raw, context) {
        Some(Value::Bool(value)) => Some(*value),
        Some(Value::String(value)) => Some(value.eq_ignore_ascii_case("true")),
        _ => None,
    }
}

fn document_resolved_template(raw: &str, context: &DocumentEvalContext<'_>) -> String {
    let mut rendered = String::new();
    let mut remaining = raw;
    while let Some(open) = remaining.find('{') {
        let (prefix, tail) = remaining.split_at(open);
        rendered.push_str(prefix);
        let tail = &tail[1..];
        let Some(close) = tail.find('}') else {
            rendered.push('{');
            rendered.push_str(tail);
            return rendered;
        };
        let key = &tail[..close];
        rendered.push_str(
            &document_resolved_value(key.trim(), context)
                .map(json_value_to_document_text)
                .or_else(|| document_template_fallback_value(key.trim(), context))
                .unwrap_or_else(|| key.trim().to_owned()),
        );
        remaining = &tail[close + 1..];
    }
    rendered.push_str(remaining);
    rendered
}

fn document_template_fallback_value(
    key: &str,
    context: &DocumentEvalContext<'_>,
) -> Option<String> {
    if key == "maybe_s" {
        let count = document_resolved_value("count", context)?.as_i64()?;
        return Some((count != 1).then_some("s").unwrap_or("").to_owned());
    }
    None
}

fn document_resolved_value<'a>(
    raw: &str,
    context: &'a DocumentEvalContext<'_>,
) -> Option<&'a Value> {
    let path = raw.strip_prefix('$').unwrap_or(raw);
    if path.is_empty() || path.contains('|') {
        return None;
    }
    let parts = path.split('.').collect::<Vec<_>>();
    let first = *parts.first()?;
    let suffix = parts.get(1..).unwrap_or_default();
    let local_origins = context.local_origins.get(first).cloned();
    let mut current = if first == "PASSED" {
        context.passed.as_ref().or(context.root)?
    } else {
        context.locals.get(first).or_else(|| {
            context
                .root
                .and_then(|root| root.as_object())
                .and_then(|object| object.get(first))
        })?
    };
    let mut row_origin_reads = BTreeSet::new();
    for (index, part) in suffix.iter().enumerate() {
        if let Some(row_origin) = document_row_origin_for_item(current) {
            let suffix_path = suffix[index..].join(".");
            if let Some(path) = document_origin_with_suffix(&row_origin, &suffix_path) {
                row_origin_reads.insert(path);
            }
        }
        current = current.as_object()?.get(*part)?;
    }
    if first == "PASSED" {
        document_context_record_data_read(context, suffix.join("."));
    } else if let Some(origins) = local_origins {
        let suffix_path = suffix.join(".");
        for origin in origins {
            if let Some(path) = document_origin_with_suffix(&origin, &suffix_path) {
                document_context_record_data_read(context, path);
            }
        }
    } else if !context.locals.contains_key(first) {
        document_context_record_data_read(context, path.to_owned());
    }
    document_context_record_data_reads(context, row_origin_reads);
    Some(current)
}

fn json_value_to_document_text(value: &Value) -> String {
    match value {
        Value::Null => String::new(),
        Value::Bool(value) => value.to_string(),
        Value::Number(value) => value.to_string(),
        Value::String(value) => value.clone(),
        Value::Array(values) => values.len().to_string(),
        Value::Object(_) => String::new(),
    }
}

