fn preview_headed_scenario_definition(id: &str) -> Option<PreviewHeadedScenarioDefinition> {
    match id {
        "counter" | "counter-basic-headed" => Some(preview_headed_counter_scenario_definition()),
        "cells" | "cells-basic-headed" => Some(preview_headed_cells_scenario_definition()),
        "todomvc" | "todomvc-visual-headed" => {
            Some(preview_headed_generic_visual_scenario_definition("todomvc"))
        }
        "todo_mvc_physical" | "todo_mvc_physical-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("todo_mvc_physical"),
        ),
        "novywave" | "novywave-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("novywave"),
        ),
        "hello_3d" | "hello_3d-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("hello_3d"),
        ),
        "printable_bracket_3d" | "printable_bracket_3d-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("printable_bracket_3d"),
        ),
        "parametric_car_3d" | "parametric_car_3d-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("parametric_car_3d"),
        ),
        "parametric_car_rich_3d" | "parametric_car_rich_3d-visual-headed" => Some(
            preview_headed_generic_visual_scenario_definition("parametric_car_rich_3d"),
        ),
        _ => None,
    }
}

fn preview_headed_scenario_required_source_path(scenario_id: &str) -> Option<&'static str> {
    match scenario_id {
        "counter-basic-headed" => Some("examples/counter.bn"),
        "cells-basic-headed" => Some("examples/cells.bn"),
        "todomvc-visual-headed" => Some("examples/todomvc.bn"),
        "todo_mvc_physical-visual-headed" => Some("examples/todo_mvc_physical/RUN.bn"),
        "novywave-visual-headed" => Some("examples/novywave/RUN.bn"),
        "hello_3d-visual-headed" => Some("examples/hello_3d/RUN.bn"),
        "printable_bracket_3d-visual-headed" => Some("examples/printable_bracket_3d/RUN.bn"),
        "parametric_car_3d-visual-headed" => Some("examples/parametric_car_3d/RUN.bn"),
        "parametric_car_rich_3d-visual-headed" => Some("examples/parametric_car_rich_3d/RUN.bn"),
        _ => None,
    }
}

impl PreviewHeadedScenarioRun {
    fn new(definition: PreviewHeadedScenarioDefinition) -> Self {
        let now = Instant::now();
        let started_at_unix_ms = unix_now_ms();
        let cursor = (96.0, 96.0);
        Self {
            overlay: PreviewHeadedScenarioOverlayState {
                scenario_id: definition.id.clone(),
                cursor_x: cursor.0,
                cursor_y: cursor.1,
                label: "Test".to_owned(),
                pressed_keys: Vec::new(),
                mouse_down: false,
                click_pulse_started_at_ms: None,
                status_text: "Running".to_owned(),
                step_text: "Starting".to_owned(),
            },
            report_steps: vec![json!({
                    "id": "start",
                    "status": "pass",
                    "started_at_unix_ms": started_at_unix_ms,
                    "runner": "preview-headed-scenario-runner",
                "scenario_api": "Rust enum steps: move mouse, click, key overlay, wait, assert runtime text"
            })],
            definition,
            status: PreviewHeadedScenarioStatus::Running,
            step_index: 0,
            started_at: now,
            step_started_at: now,
            step_start_cursor: cursor,
            cursor,
            failures: Vec::new(),
            completed_at_unix_ms: None,
        }
    }

    fn active(&self) -> bool {
        self.status == PreviewHeadedScenarioStatus::Running
    }

    fn report(&self) -> serde_json::Value {
        json!({
            "kind": "headed-scenario-report",
            "status": match self.status {
                PreviewHeadedScenarioStatus::Running => "running",
                PreviewHeadedScenarioStatus::Pass => "pass",
                PreviewHeadedScenarioStatus::Fail => "fail",
            },
            "scenario_id": self.definition.id,
            "scenario_label": self.definition.label,
            "step_index": self.step_index,
            "step_count": self.definition.steps.len(),
            "steps": self.report_steps,
            "failures": self.failures,
            "failure_categories": [
                "runtime_assertion",
                "visual_readback",
                "event_routing",
                "timeout",
                "cancellation"
            ],
            "overlay": {
                "rendered_by": "preview LayoutFrame -> boon_native_gpu WGPU render scene",
                "cursor_visible": true,
                "click_feedback_visible": true,
                "key_hud_visible": true,
                "current": preview_headed_scenario_overlay_report(&self.overlay)
            },
            "input_route_contract": "headed scenario step -> app-owned NativeInputAdapterProof -> preview_apply_real_window_input_with_units -> document hit region -> LiveRuntime",
            "direct_runtime_state_mutation": false,
            "completed_at_unix_ms": self.completed_at_unix_ms
        })
    }

    fn finish_pass_if_done(&mut self) {
        if self.step_index >= self.definition.steps.len()
            && self.status == PreviewHeadedScenarioStatus::Running
        {
            self.status = PreviewHeadedScenarioStatus::Pass;
            self.completed_at_unix_ms = Some(unix_now_ms());
            self.overlay.status_text = "Pass".to_owned();
            self.overlay.step_text = format!("{} completed", self.definition.label);
            self.report_steps.push(json!({
                "id": "finish",
                "status": "pass",
                "completed_at_unix_ms": self.completed_at_unix_ms
            }));
        }
    }

    fn fail(&mut self, category: &str, detail: String) {
        self.status = PreviewHeadedScenarioStatus::Fail;
        self.completed_at_unix_ms = Some(unix_now_ms());
        self.overlay.status_text = "Fail".to_owned();
        self.overlay.step_text = detail.clone();
        self.failures.push(json!({
            "category": category,
            "step_index": self.step_index,
            "detail": detail
        }));
    }

    fn advance_step(&mut self, now: Instant, report: serde_json::Value) {
        self.report_steps.push(report);
        self.step_index = self.step_index.saturating_add(1);
        self.step_started_at = now;
        self.step_start_cursor = self.cursor;
        self.overlay.pressed_keys.clear();
        self.overlay.mouse_down = false;
        self.finish_pass_if_done();
    }
}

fn preview_headed_scenario_overlay_report(
    overlay: &PreviewHeadedScenarioOverlayState,
) -> serde_json::Value {
    json!({
        "scenario_id": overlay.scenario_id,
        "cursor_x": overlay.cursor_x,
        "cursor_y": overlay.cursor_y,
        "label": overlay.label,
        "pressed_keys": overlay.pressed_keys,
        "mouse_down": overlay.mouse_down,
        "click_pulse_visible": overlay.click_pulse_started_at_ms.is_some(),
        "status_text": overlay.status_text,
        "step_text": overlay.step_text
    })
}

fn preview_headed_scenario_overlay() -> Option<PreviewHeadedScenarioOverlayState> {
    preview_headed_scenario_state()
        .lock()
        .ok()
        .and_then(|state| state.as_ref().map(|run| run.overlay.clone()))
}

fn preview_headed_scenario_report_path(scenario_id: &str) -> PathBuf {
    PathBuf::from(format!(
        "target/reports/native-gpu/headed-scenario-{scenario_id}.json"
    ))
}

fn write_preview_headed_scenario_report(run: &PreviewHeadedScenarioRun) {
    let path = preview_headed_scenario_report_path(&run.definition.id);
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let _ = std::fs::write(
        &path,
        serde_json::to_vec_pretty(&run.report()).unwrap_or_default(),
    );
}

fn preview_start_headed_scenario_response(
    state: &Arc<Mutex<PreviewIpcState>>,
    request: &serde_json::Value,
) -> Result<serde_json::Value, Box<dyn std::error::Error>> {
    let scenario_id = request
        .get("scenario_id")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("counter");
    let definition = preview_headed_scenario_definition(scenario_id)
        .ok_or_else(|| format!("unknown headed scenario `{scenario_id}`"))?;
    let source_path = state
        .lock()
        .map_err(|_| "preview IPC state mutex poisoned")?
        .source_path
        .clone();
    if let Some(required_path) = preview_headed_scenario_required_source_path(&definition.id) {
        let source_path_text = source_path.to_string_lossy();
        if !source_path_text.ends_with(required_path) {
            return Ok(json!({
                "kind": "headed-scenario-start-ack",
                "status": "fail",
                "scenario_id": definition.id,
                "failure_category": "event_routing",
                "diagnostic": format!(
                    "Headed scenario `{}` requires the preview to be running {}, current source is {}",
                    definition.id,
                    required_path,
                    source_path.display()
                ),
                "preview_pid": std::process::id()
            }));
        }
    }
    let run = PreviewHeadedScenarioRun::new(definition);
    let report_path = preview_headed_scenario_report_path(&run.definition.id);
    write_preview_headed_scenario_report(&run);
    *preview_headed_scenario_state()
        .lock()
        .map_err(|_| "preview headed scenario mutex poisoned")? = Some(run.clone());
    Ok(json!({
        "kind": "headed-scenario-start-ack",
        "status": "pass",
        "scenario_id": run.definition.id,
        "scenario_label": run.definition.label,
        "report_path": report_path,
        "overlay_rendered_by": "preview LayoutFrame -> boon_native_gpu WGPU render scene",
        "direct_runtime_state_mutation": false,
        "preview_pid": std::process::id()
    }))
}

fn preview_headed_scenario_status_response() -> serde_json::Value {
    match preview_headed_scenario_state().lock() {
        Ok(state) => state
            .as_ref()
            .map(PreviewHeadedScenarioRun::report)
            .unwrap_or_else(|| {
                json!({
                    "kind": "headed-scenario-report",
                    "status": "idle",
                    "scenario_id": null
                })
            }),
        Err(_) => json!({
            "kind": "headed-scenario-report",
            "status": "fail",
            "failure_category": "runtime_assertion",
            "diagnostic": "preview headed scenario mutex poisoned"
        }),
    }
}

const PREVIEW_DRAG_STEP_PX: f64 = 18.0;
const PREVIEW_DRAG_MAX_EVENTS_PER_INPUT: usize = 8;

fn unhandled_primary_mouse_presses(
    input: &boon_native_app_window::NativeInputAdapterProof,
    last_seen_sequence: u64,
) -> Vec<boon_native_app_window::NativeMouseButtonEventProof> {
    input
        .mouse_button_events
        .iter()
        .filter(|event| {
            event.sequence > last_seen_sequence && event.button == "left" && event.pressed
        })
        .cloned()
        .collect()
}

fn unhandled_primary_mouse_releases(
    input: &boon_native_app_window::NativeInputAdapterProof,
    last_seen_sequence: u64,
) -> Vec<boon_native_app_window::NativeMouseButtonEventProof> {
    let releases = input
        .mouse_button_events
        .iter()
        .filter(|event| {
            event.sequence > last_seen_sequence && event.button == "left" && !event.pressed
        })
        .cloned()
        .collect::<Vec<_>>();
    if !releases.is_empty() || !input.mouse_button_events.is_empty() {
        return releases;
    }
    if input.mouse_button_event_count > last_seen_sequence && input.mouse_buttons_down.is_empty() {
        vec![boon_native_app_window::NativeMouseButtonEventProof {
            sequence: input.mouse_button_event_count,
            button: "left".to_owned(),
            pressed: false,
            window_protocol_id: input.mouse_last_window_protocol_id,
        }]
    } else {
        Vec::new()
    }
}

fn unhandled_primary_mouse_click_edges(
    input: &boon_native_app_window::NativeInputAdapterProof,
    last_press_sequence: u64,
    last_release_sequence: u64,
) -> Vec<boon_native_app_window::NativeMouseButtonEventProof> {
    let releases = unhandled_primary_mouse_releases(input, last_release_sequence);
    if !releases.is_empty() {
        return releases;
    }
    unhandled_primary_mouse_presses(input, last_press_sequence)
}

fn preview_simple_click_shape_reject_reason(
    input: &boon_native_app_window::NativeInputAdapterProof,
    input_state: &PreviewNativeInputState,
    press_count: usize,
    release_count: usize,
    click_edge_count: usize,
) -> &'static str {
    if click_edge_count == 0 {
        if input
            .mouse_buttons_down
            .iter()
            .any(|button| button == "left")
            && input.mouse_motion_event_count > input_state.last_mouse_motion_event_count
        {
            "held_motion_without_click_edge"
        } else {
            "missing_click_edge"
        }
    } else if release_count == 0 && press_count > 1 {
        "multiple_press_edges_without_release"
    } else if press_count > click_edge_count.saturating_add(1) {
        "ambiguous_primary_press_batch"
    } else {
        "ambiguous_primary_click_batch"
    }
}

fn push_repeated_live_source_event(
    events: &mut Vec<boon_runtime::LiveSourceEvent>,
    event: boon_runtime::LiveSourceEvent,
    repeat_count: usize,
) {
    for _ in 0..repeat_count.max(1) {
        events.push(event.clone());
    }
}

fn preview_input_has_unhandled_source_events(
    input: &boon_native_app_window::NativeInputAdapterProof,
    input_state: &PreviewNativeInputState,
) -> bool {
    if input.synthetic_input_probe {
        return false;
    }
    input.mouse_motion_event_count > input_state.last_mouse_motion_event_count
        || preview_mouse_position_key(input.mouse_window_pos)
            != input_state.last_hover_window_position
        || !unhandled_primary_mouse_presses(input, input_state.last_mouse_press_event_count)
            .is_empty()
        || !unhandled_primary_mouse_click_edges(
            input,
            input_state.last_mouse_press_event_count,
            input_state.last_mouse_button_event_count,
        )
        .is_empty()
        || input
            .keyboard_events
            .iter()
            .any(|event| event.sequence > input_state.last_keyboard_event_sequence)
        || input_state.held_repeat_key.as_ref().is_some_and(|key| {
            input_state.held_repeat_next_at.is_some()
                && input
                    .pressed_keys
                    .iter()
                    .any(|pressed| pressed_key_matches_repeat(pressed, key))
        })
}

fn preview_input_is_unhandled_primary_press_only(
    input: &boon_native_app_window::NativeInputAdapterProof,
    input_state: &PreviewNativeInputState,
) -> bool {
    let presses = unhandled_primary_mouse_presses(input, input_state.last_mouse_press_event_count);
    !presses.is_empty()
        && unhandled_primary_mouse_releases(input, input_state.last_mouse_button_event_count)
            .is_empty()
        && input.keyboard_events.is_empty()
        && input.pressed_keys.is_empty()
        && input.scroll_delta_x.abs() <= f64::EPSILON
        && input.scroll_delta_y.abs() <= f64::EPSILON
        && input_state.active_drag.is_none()
        && input_state.pending_live_events.is_empty()
        && input.mouse_motion_event_count <= input_state.last_mouse_motion_event_count
        && preview_mouse_position_key(input.mouse_window_pos)
            == input_state.last_hover_window_position
}

fn preview_mouse_position_key(
    position: Option<boon_native_app_window::NativeMouseWindowPosition>,
) -> Option<(u64, u64, u64, u64)> {
    position.map(|position| {
        (
            position.x.to_bits(),
            position.y.to_bits(),
            position.window_width.to_bits(),
            position.window_height.to_bits(),
        )
    })
}

fn deterministic_click_input(
    event_count: u64,
    x: f64,
    y: f64,
) -> boon_native_app_window::NativeInputAdapterProof {
    deterministic_click_input_from_start_index(0, event_count, x, y)
}

fn deterministic_click_input_from_index(
    index: u64,
    x: f64,
    y: f64,
) -> boon_native_app_window::NativeInputAdapterProof {
    deterministic_click_input_from_start_index(index, 1, x, y)
}

fn real_window_shaped_click_input_from_index(
    index: u64,
    x: f64,
    y: f64,
) -> boon_native_app_window::NativeInputAdapterProof {
    let mut input = deterministic_click_input_from_index(index, x, y);
    input.capture_scope = "app_window_coalesced_input_with_per_window_event_provenance".to_owned();
    input.input_injection_method =
        "deterministic_app_owned_mouse_event_batch_with_stale_sampled_button_state".to_owned();
    input.mouse_buttons_down = vec!["left".to_owned()];
    input
}

fn deterministic_click_input_from_start_index(
    start_index: u64,
    event_count: u64,
    x: f64,
    y: f64,
) -> boon_native_app_window::NativeInputAdapterProof {
    let mut mouse_button_events = Vec::new();
    for index in 0..event_count {
        let absolute_index = start_index.saturating_add(index);
        let press_sequence = absolute_index.saturating_mul(2).saturating_add(1);
        let release_sequence = press_sequence.saturating_add(1);
        mouse_button_events.push(boon_native_app_window::NativeMouseButtonEventProof {
            sequence: press_sequence,
            button: "left".to_owned(),
            pressed: true,
            window_protocol_id: Some(1),
        });
        mouse_button_events.push(boon_native_app_window::NativeMouseButtonEventProof {
            sequence: release_sequence,
            button: "left".to_owned(),
            pressed: false,
            window_protocol_id: Some(1),
        });
    }
    let last_sequence = start_index.saturating_add(event_count).saturating_mul(2);
    boon_native_app_window::NativeInputAdapterProof {
        installed: true,
        capture_scope: "deterministic_recent_mouse_button_events".to_owned(),
        keyboard_api: "none".to_owned(),
        mouse_api: "app_window::input::mouse::Mouse::event_provenance".to_owned(),
        wheel_api: "none".to_owned(),
        per_window_event_provenance_api:
            "app_window::input::mouse::MouseEventProvenance::recent_button_events".to_owned(),
        sampled_after_visible_window: true,
        real_os_events_observed: true,
        input_injection_method: "deterministic_app_owned_mouse_event_batch".to_owned(),
        synthetic_input_probe: false,
        mouse_last_window_protocol_id: Some(1),
        keyboard_last_window_protocol_id: None,
        mouse_motion_event_count: 1,
        mouse_button_event_count: last_sequence,
        mouse_scroll_event_count: 0,
        mouse_total_event_count: last_sequence.saturating_add(1),
        keyboard_key_event_count: 0,
        mouse_button_events,
        keyboard_events: Vec::new(),
        mouse_window_pos: Some(boon_native_app_window::NativeMouseWindowPosition {
            x,
            y,
            window_width: 920.0,
            window_height: 720.0,
        }),
        mouse_buttons_down: Vec::new(),
        pressed_keys: Vec::new(),
        scroll_delta_x: 0.0,
        scroll_delta_y: 0.0,
    }
}

fn preview_apply_deterministic_drag_motion_with_units(
    source_path: &Path,
    source_text: &str,
    runtime_units: &[boon_runtime::RuntimeSourceUnit],
    live_runtime: &Arc<Mutex<boon_runtime::LiveRuntime>>,
    shared_render_state: &Arc<Mutex<PreviewSharedRenderState>>,
    input_state: &mut PreviewNativeInputState,
    source_event: &str,
    delta_x: f64,
    delta_y: f64,
    viewport: (f32, f32),
) -> Result<f64, Box<dyn std::error::Error>> {
    let layout_proof = shared_render_state
        .lock()
        .map_err(|_| "preview render state mutex poisoned")?
        .layout_proof
        .clone();
    let (start_x, start_y, _) = source_hit_center(&layout_proof, source_event)?;
    let end_x = start_x + delta_x;
    let end_y = start_y + delta_y;
    let press_sequence = input_state.last_mouse_button_event_count.saturating_add(1);
    let release_sequence = press_sequence.saturating_add(1);
    let motion_base = input_state.last_mouse_motion_event_count;

    let mut press = deterministic_click_input(0, start_x, start_y);
    set_input_window_size(&mut press, viewport);
    press.mouse_motion_event_count = motion_base.saturating_add(1);
    press.mouse_button_event_count = press_sequence;
    press.mouse_total_event_count = press_sequence.saturating_add(1);
    press.mouse_buttons_down = vec!["left".to_owned()];
    press.mouse_button_events = vec![boon_native_app_window::NativeMouseButtonEventProof {
        sequence: press_sequence,
        button: "left".to_owned(),
        pressed: true,
        window_protocol_id: Some(1),
    }];
    preview_apply_real_window_input_with_units(
        &press,
        source_path,
        source_text,
        runtime_units,
        Some(live_runtime),
        shared_render_state,
        input_state,
    )?;

    let mut drag = deterministic_click_input(0, end_x, end_y);
    set_input_window_size(&mut drag, viewport);
    drag.mouse_motion_event_count = motion_base.saturating_add(2);
    drag.mouse_button_event_count = press_sequence;
    drag.mouse_total_event_count = press_sequence.saturating_add(2);
    drag.mouse_buttons_down = vec!["left".to_owned()];
    drag.mouse_button_events.clear();
    let started = Instant::now();
    preview_apply_real_window_input_with_units(
        &drag,
        source_path,
        source_text,
        runtime_units,
        Some(live_runtime),
        shared_render_state,
        input_state,
    )?;
    let drag_ms = started.elapsed().as_secs_f64() * 1_000.0;

    let mut release = deterministic_click_input(0, end_x, end_y);
    set_input_window_size(&mut release, viewport);
    release.mouse_motion_event_count = motion_base.saturating_add(3);
    release.mouse_button_event_count = release_sequence;
    release.mouse_total_event_count = release_sequence.saturating_add(1);
    release.mouse_button_events = vec![boon_native_app_window::NativeMouseButtonEventProof {
        sequence: release_sequence,
        button: "left".to_owned(),
        pressed: false,
        window_protocol_id: Some(1),
    }];
    release.mouse_buttons_down.clear();
    preview_apply_real_window_input_with_units(
        &release,
        source_path,
        source_text,
        runtime_units,
        Some(live_runtime),
        shared_render_state,
        input_state,
    )?;

    Ok(drag_ms)
}

fn preview_take_drag_events_from_input(
    layout_proof: &Value,
    input: &boon_native_app_window::NativeInputAdapterProof,
    _live_runtime: &Arc<Mutex<boon_runtime::LiveRuntime>>,
    input_state: &mut PreviewNativeInputState,
) -> Vec<boon_runtime::LiveSourceEvent> {
    let route_table = PreviewHitRouteTable::from_layout_proof(layout_proof);
    for press in unhandled_primary_mouse_presses(input, input_state.last_mouse_press_event_count) {
        input_state.last_mouse_press_event_count =
            input_state.last_mouse_press_event_count.max(press.sequence);
        let Some(position) = input.mouse_window_pos else {
            continue;
        };
        if let Some(route_table) = route_table.as_ref()
            && let Some(hit) = route_table.hit_test(position.x, position.y)
            && let Some(source_node) = route_table.source_node_for_hit(hit, &["drag"])
            && let Some(source) = route_table.source_for_node_intent(&source_node, "drag")
        {
            input_state.active_drag = Some(PreviewActiveDrag {
                address: route_table.address(&source_node),
                target_text: route_table.target_text(&source_node),
                target_occurrence: route_table.target_occurrence_for_source(&source_node, &source),
                target_key: route_table.target_key(&source_node),
                target_generation: route_table.target_generation(&source_node),
                source,
                last_x: position.x,
                last_y: position.y,
            });
            continue;
        }
        let Some(hit_region) = document_hit_region_at(layout_proof, position.x, position.y) else {
            continue;
        };
        let Some(source_node) =
            live_source_node_for_hit_region_with_intents(layout_proof, &hit_region, &["drag"])
        else {
            continue;
        };
        let Some(source) = live_source_for_node_intent(layout_proof, &source_node, "drag") else {
            continue;
        };
        input_state.active_drag = Some(PreviewActiveDrag {
            address: focused_address(layout_proof, &source_node),
            target_text: focused_target_text(layout_proof, &source_node),
            target_occurrence: focused_target_occurrence_for_source(
                layout_proof,
                &source_node,
                &source,
            ),
            target_key: layout_row_key_for_node(layout_proof, &source_node),
            target_generation: layout_row_generation_for_node(layout_proof, &source_node),
            source,
            last_x: position.x,
            last_y: position.y,
        });
    }

    let left_button_down = input
        .mouse_buttons_down
        .iter()
        .any(|button| button == "left");
    if !left_button_down {
        return Vec::new();
    }
    let Some(position) = input.mouse_window_pos else {
        return Vec::new();
    };
    let Some(active_drag) = input_state.active_drag.as_mut() else {
        return Vec::new();
    };
    let texts = preview_drag_payload_texts(active_drag, position.x, position.y);
    texts
        .into_iter()
        .map(|text| preview_drag_live_event(active_drag, text))
        .collect()
}

fn preview_drag_payload_texts(
    active_drag: &mut PreviewActiveDrag,
    x: f64,
    y: f64,
) -> Vec<&'static str> {
    let delta_x = x - active_drag.last_x;
    let delta_y = y - active_drag.last_y;
    let horizontal = delta_x.abs() >= delta_y.abs();
    let delta = if horizontal { delta_x } else { delta_y };
    let steps = (delta.abs() / PREVIEW_DRAG_STEP_PX)
        .floor()
        .min(PREVIEW_DRAG_MAX_EVENTS_PER_INPUT as f64) as usize;
    if steps == 0 {
        return Vec::new();
    }
    let direction = if delta >= 0.0 { "Grow" } else { "Shrink" };
    let consumed = delta.signum() * PREVIEW_DRAG_STEP_PX * steps as f64;
    if horizontal {
        active_drag.last_x += consumed;
        active_drag.last_y = y;
    } else {
        active_drag.last_x = x;
        active_drag.last_y += consumed;
    }
    (0..steps).map(|_| direction).collect()
}

fn preview_drag_live_event(
    active_drag: &PreviewActiveDrag,
    text: &str,
) -> boon_runtime::LiveSourceEvent {
    boon_runtime::LiveSourceEvent {
        source: active_drag.source.clone(),
        text: Some(text.to_owned()),
        key: None,
        address: active_drag.address.clone(),
        target_text: active_drag.target_text.clone(),
        target_occurrence: active_drag.target_occurrence,
        target_key: active_drag.target_key,
        target_generation: active_drag.target_generation,
        ..boon_runtime::LiveSourceEvent::default()
    }
}

fn source_hit_center(
    layout_proof: &Value,
    source_event: &str,
) -> Result<(f64, f64, String), Box<dyn std::error::Error>> {
    source_hit_center_for_target(layout_proof, source_event, None)
}

#[cfg(test)]
fn source_hit_center_for_address(
    layout_proof: &Value,
    source_event: &str,
    address: &str,
) -> Result<(f64, f64, String), Box<dyn std::error::Error>> {
    source_hit_center_for_target(layout_proof, source_event, Some(address))
}

fn source_hit_center_for_target(
    layout_proof: &Value,
    source_event: &str,
    target: Option<&str>,
) -> Result<(f64, f64, String), Box<dyn std::error::Error>> {
    let source_intents_from_snapshot;
    let source_intents = if let Some(source_intents) = layout_proof
        .get("source_intent_assertions")
        .and_then(serde_json::Value::as_array)
    {
        source_intents
    } else {
        let layout_hash = layout_proof
            .get("layout_frame_hash")
            .and_then(serde_json::Value::as_str)
            .ok_or("layout proof missing source intents and layout hash")?;
        let snapshot = cached_document_render_snapshot(layout_hash)
            .ok_or("layout proof missing source intents and cached render snapshot")?;
        source_intents_from_snapshot = snapshot.source_intents.clone();
        &source_intents_from_snapshot
    };
    let hit_regions = layout_proof
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)
        .map(Vec::as_slice)
        .unwrap_or(&[]);
    let target_node = source_intents
        .iter()
        .find_map(|intent| {
            if intent
                .get("source_path")
                .and_then(serde_json::Value::as_str)
                == Some(source_event)
                && target.is_none_or(|target| {
                    source_intent_has_exact_value(intent, source_intents, "target", target)
                })
            {
                intent
                    .get("node")
                    .and_then(serde_json::Value::as_str)
                    .map(str::to_owned)
            } else {
                None
            }
        })
        .or_else(|| {
            let target_event = target
                .map(|target| json!({ "address": target }))
                .unwrap_or_else(|| json!({}));
            source_intents.iter().find_map(|intent| {
                if intent
                    .get("source_path")
                    .and_then(serde_json::Value::as_str)
                    == Some(source_event)
                    && source_intent_matches_event_target_with_regions(
                        intent,
                        source_intents,
                        hit_regions,
                        &target_event,
                    )
                {
                    intent
                        .get("node")
                        .and_then(serde_json::Value::as_str)
                        .map(str::to_owned)
                } else {
                    None
                }
            })
        })
        .ok_or_else(|| {
            let nearby = source_intents
                .iter()
                .filter_map(|intent| {
                    let source_path = intent
                        .get("source_path")
                        .and_then(serde_json::Value::as_str)?;
                    (source_path.contains(source_event)
                        || source_event.contains(source_path)
                        || source_path
                            .rsplit_once('.')
                            .is_some_and(|(prefix, _)| prefix == source_event))
                    .then(|| {
                        json!({
                            "node": intent.get("node").cloned().unwrap_or_else(|| json!(null)),
                            "intent": intent.get("intent").cloned().unwrap_or_else(|| json!(null)),
                            "source_path": source_path
                        })
                    })
                })
                .take(12)
                .collect::<Vec<_>>();
            let sample = source_intents
                .iter()
                .filter_map(|intent| {
                    Some(json!({
                        "node": intent.get("node").cloned().unwrap_or_else(|| json!(null)),
                        "intent": intent.get("intent").cloned().unwrap_or_else(|| json!(null)),
                        "source_path": intent.get("source_path")?.clone()
                    }))
                })
                .take(20)
                .collect::<Vec<_>>();
            format!(
                "source event `{source_event}` has no document source intent for target {:?}; nearby={}; sample={}",
                target,
                serde_json::to_string(&nearby).unwrap_or_else(|_| "[]".to_owned()),
                serde_json::to_string(&sample).unwrap_or_else(|_| "[]".to_owned())
            )
        })?;
    if let Some(hit_region) = layout_proof
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)
        .into_iter()
        .flatten()
        .find(|region| {
            region.get("node").and_then(serde_json::Value::as_str) == Some(target_node.as_str())
        })
    {
        let bounds = hit_region
            .get("bounds")
            .ok_or("target hit region missing bounds")?;
        let x = bounds
            .get("x")
            .and_then(serde_json::Value::as_f64)
            .unwrap_or_default()
            + bounds
                .get("width")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or_default()
                / 2.0;
        let y = bounds
            .get("y")
            .and_then(serde_json::Value::as_f64)
            .unwrap_or_default()
            + bounds
                .get("height")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or_default()
                / 2.0;
        return Ok((x, y, target_node));
    }
    let route_table = PreviewHitRouteTable::from_layout_proof(layout_proof)
        .ok_or_else(|| format!("source event `{source_event}` target has no hit region"))?;
    let hit = route_table
        .hit_for_node(&target_node)
        .ok_or_else(|| format!("source event `{source_event}` target has no typed hit region"))?;
    let x = f64::from(hit.bounds.x + hit.bounds.width / 2.0);
    let y = f64::from(hit.bounds.y + hit.bounds.height / 2.0);
    Ok((x, y, target_node))
}

fn formula_bar_input_center(
    layout_proof: &Value,
) -> Result<(f64, f64, String), Box<dyn std::error::Error>> {
    if let Some(display_items) = layout_proof
        .get("display_item_samples")
        .and_then(serde_json::Value::as_array)
    {
        let item = display_items
            .iter()
            .find(|item| {
                item.get("kind").and_then(serde_json::Value::as_str) == Some("text_input")
                    && item
                        .pointer("/bounds/y")
                        .and_then(serde_json::Value::as_f64)
                        .is_some_and(|y| y < 50.0)
                    && item
                        .pointer("/bounds/width")
                        .and_then(serde_json::Value::as_f64)
                        .is_some_and(|width| width > 200.0)
            })
            .ok_or("formula bar text input should be present")?;
        let node = item
            .get("node")
            .and_then(serde_json::Value::as_str)
            .ok_or("formula bar text input missing node")?
            .to_owned();
        if let Some(hit_region) = layout_proof
            .get("hit_target_assertions")
            .and_then(serde_json::Value::as_array)
            .into_iter()
            .flatten()
            .find(|hit| hit.get("node").and_then(serde_json::Value::as_str) == Some(node.as_str()))
        {
            let bounds = hit_region
                .get("bounds")
                .ok_or("formula bar input hit target missing bounds")?;
            let x = bounds
                .get("x")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or_default()
                + bounds
                    .get("width")
                    .and_then(serde_json::Value::as_f64)
                    .unwrap_or_default()
                    / 2.0;
            let y = bounds
                .get("y")
                .and_then(serde_json::Value::as_f64)
                .unwrap_or_default()
                + bounds
                    .get("height")
                    .and_then(serde_json::Value::as_f64)
                    .unwrap_or_default()
                    / 2.0;
            return Ok((x, y, node));
        }
    }
    let route_table = PreviewHitRouteTable::from_layout_proof(layout_proof)
        .ok_or("formula bar input has no hit target and no typed route table")?;
    let node = route_table
        .display_items
        .iter()
        .find(|item| {
            matches!(item.kind, boon_document_model::DocumentNodeKind::TextInput)
                && item.bounds.y < 50.0
                && item.bounds.width > 200.0
        })
        .map(|item| item.node.0.clone())
        .ok_or("formula bar text input should be present in typed route table")?;
    let hit = route_table
        .hit_for_node(&node)
        .ok_or("formula bar input has no typed hit target")?;
    let x = f64::from(hit.bounds.x + hit.bounds.width / 2.0);
    let y = f64::from(hit.bounds.y + hit.bounds.height / 2.0);
    Ok((x, y, node))
}

fn source_hit_width_for_node(
    layout_proof: &Value,
    target_node: &str,
) -> Result<f64, Box<dyn std::error::Error>> {
    layout_proof
        .get("hit_target_assertions")
        .and_then(serde_json::Value::as_array)
        .and_then(|regions| {
            regions.iter().find_map(|region| {
                (region.get("node").and_then(serde_json::Value::as_str) == Some(target_node))
                    .then(|| {
                        region
                            .pointer("/bounds/width")
                            .and_then(serde_json::Value::as_f64)
                    })
                    .flatten()
            })
        })
        .ok_or_else(|| format!("layout proof missing hit width for node `{target_node}`").into())
}

fn source_intent_has_exact_value(
    intent: &serde_json::Value,
    source_intents: &[serde_json::Value],
    expected_intent: &str,
    expected_value: &str,
) -> bool {
    let Some(node) = intent.get("node").and_then(serde_json::Value::as_str) else {
        return false;
    };
    source_intents.iter().any(|candidate| {
        candidate.get("node").and_then(serde_json::Value::as_str) == Some(node)
            && candidate.get("intent").and_then(serde_json::Value::as_str) == Some(expected_intent)
            && candidate
                .get("source_path")
                .and_then(serde_json::Value::as_str)
                == Some(expected_value)
    })
}

fn preview_reset_caret_blink(input_state: &mut PreviewNativeInputState) {
    input_state.caret_blink_started_at = Some(Instant::now());
}

fn preview_caret_visible(input_state: &PreviewNativeInputState, now: Instant) -> bool {
    let Some(started_at) = input_state.caret_blink_started_at else {
        return true;
    };
    (now.duration_since(started_at).as_millis() / 500).is_multiple_of(2)
}

fn preview_text_input_should_replace_on_type(layout_proof: &Value, node: &str) -> bool {
    !preview_text_input_live_change_enabled(layout_proof, node)
}

fn preview_text_input_live_change_enabled(layout_proof: &Value, node: &str) -> bool {
    document_display_item_style_bool(layout_proof, node, "input_live_change").unwrap_or(true)
}

fn document_display_item_style_bool(layout_proof: &Value, node: &str, key: &str) -> Option<bool> {
    layout_proof
        .get("display_item_samples")
        .or_else(|| layout_proof.get("display_list"))
        .and_then(serde_json::Value::as_array)
        .into_iter()
        .flatten()
        .find_map(|item| {
            let item_node = item.get("node").and_then(serde_json::Value::as_str)?;
            if item_node != node {
                return None;
            }
            item.get("style")?.get(key)?.as_bool()
        })
}

fn preview_key_down_source_for_node(layout_proof: &Value, node: &str) -> Option<String> {
    live_source_for_node_intent(layout_proof, node, "key_down")
}

