    fn find_document_field<'a>(
        statement: &'a AstStatement,
        name: &str,
        expressions: &[AstExpr],
    ) -> Option<&'a AstStatement> {
        let _ = expressions;
        if document_field_name(statement).as_deref() == Some(name) {
            return Some(statement);
        }
        statement
            .children
            .iter()
            .find_map(|child| find_document_field(child, name, expressions))
    }

