    fn mirror_physical_todomvc_seed_root_fields(state: &mut serde_json::Value) {
        derive_physical_todomvc_seed_store_fields(state);
        for field in [
            "todos",
            "active_count",
            "completed_count",
            "has_todos",
            "has_completed",
            "all_completed",
            "selected_filter",
            "selected_todo_id",
            "title_to_save",
        ] {
            if state.get(field).is_some() {
                continue;
            }
            if let Some(value) = state
                .get("store")
                .and_then(|store| store.get(field))
                .cloned()
            {
                state[field] = value;
            }
        }
    }

    fn derive_physical_todomvc_seed_store_fields(state: &mut serde_json::Value) {
        let Some(todos) = state
            .pointer("/store/todos")
            .and_then(serde_json::Value::as_array)
        else {
            return;
        };
        let completed_count = todos
            .iter()
            .filter(|todo| todo["completed"].as_bool() == Some(true))
            .count();
        let active_count = todos.len().saturating_sub(completed_count);
        let Some(store) = state
            .get_mut("store")
            .and_then(serde_json::Value::as_object_mut)
        else {
            return;
        };
        store
            .entry("active_count")
            .or_insert_with(|| json!(active_count));
        store
            .entry("completed_count")
            .or_insert_with(|| json!(completed_count));
        store
            .entry("has_todos")
            .or_insert_with(|| json!(active_count > 0 || completed_count > 0));
        store
            .entry("has_completed")
            .or_insert_with(|| json!(completed_count > 0));
        store
            .entry("all_completed")
            .or_insert_with(|| json!(active_count == 0 && completed_count > 0));
    }

    #[test]
    fn physical_todomvc_add_todo_accepts_keyboard_submit() {
        let source_path = repo_path("examples/todo_mvc_physical/RUN.bn");
        let source =
            std::fs::read_to_string(&source_path).expect("physical TodoMVC source should exist");
        let live_runtime = Arc::new(Mutex::new(
            live_runtime_from_source_text("physical-todomvc-add-todo", &source_path, &source)
                .expect("physical TodoMVC runtime should initialize"),
        ));
        let state_summary = live_runtime.lock().unwrap().document_state_summary();
        let (layout_proof, layout_frame) = native_document_layout_proof_with_state_embedded(
            &source_path,
            &source,
            Some(&state_summary),
        )
        .expect("physical TodoMVC layout should lower");
        let (input_x, input_y, input_node) =
            source_hit_center(&layout_proof, "store.elements.new_todo_title_text_input")
                .expect("new todo input should have a hit region");
        let shared_render_state = Arc::new(Mutex::new(PreviewSharedRenderState {
            layout_proof,
            layout_frame_override: Some(Arc::new(layout_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        }));
        let mut input_state = PreviewNativeInputState::default();

        preview_apply_real_window_input(
            &deterministic_click_input_from_index(0, input_x, input_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking the new todo input should focus it");
        assert_eq!(
            input_state.focused_node.as_deref(),
            Some(input_node.as_str())
        );

        let typed = test_keyboard_input(
            "ship physical"
                .chars()
                .enumerate()
                .map(|(index, character)| {
                    test_key_press(index.saturating_add(1) as u64, &character.to_string())
                })
                .collect(),
            Vec::new(),
        );
        preview_apply_real_window_input(
            &typed,
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("typing a todo title should dispatch change events");
        assert_eq!(input_state.focused_text, "ship physical");

        let enter = test_keyboard_input(vec![test_key_press(30, "Return")], Vec::new());
        preview_apply_real_window_input(
            &enter,
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("pressing Enter should submit the new todo");

        let summary = live_runtime.lock().unwrap().document_state_summary();
        let todos = summary["todos"]
            .as_array()
            .expect("physical TodoMVC state should expose todos");
        let added_todo = todos
            .iter()
            .find(|todo| todo["title"].as_str() == Some("ship physical"))
            .unwrap_or_else(|| {
                panic!("submitted todo should be present in runtime state: {todos:?}")
            });
        assert_eq!(
            added_todo["completed"], false,
            "new physical todos should be active by default"
        );
        assert_eq!(
            input_state.focused_text, "",
            "new todo input should clear after a successful submit"
        );
        let frame = latest_preview_frame(&shared_render_state);
        assert!(
            frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("ship physical")),
            "submitted todo title should be visible in the preview frame"
        );
        assert_physical_todomvc_preview_healthy(&shared_render_state, "after add todo submit");

        let checkbox_layout = shared_render_state.lock().unwrap().layout_proof.clone();
        let (checkbox_x, checkbox_y, _) = source_hit_center_for_target(
            &checkbox_layout,
            "todo.todo_elements.todo_checkbox",
            Some("ship physical"),
        )
        .expect("newly appended todo should expose a checkbox hit region");
        preview_apply_real_window_input(
            &deterministic_click_input_from_index(1, checkbox_x, checkbox_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking the appended todo checkbox should dispatch a source event");
        let toggled_summary = live_runtime.lock().unwrap().document_state_summary();
        let toggled_todos = toggled_summary["todos"]
            .as_array()
            .expect("physical TodoMVC state should expose todos after toggle");
        let toggled_todo = toggled_todos
            .iter()
            .find(|todo| todo["title"].as_str() == Some("ship physical"))
            .expect("submitted todo should remain present after checkbox toggle");
        assert_eq!(
            toggled_todo["completed"], true,
            "newly appended todo should remain toggleable"
        );
        assert_physical_todomvc_preview_healthy(&shared_render_state, "after toggling added todo");
    }

    #[test]
    fn physical_todomvc_toggle_all_completes_then_clears_every_row() {
        let source_path = repo_path("examples/todo_mvc_physical/RUN.bn");
        let source =
            std::fs::read_to_string(&source_path).expect("physical TodoMVC source should exist");
        let live_runtime = Arc::new(Mutex::new(
            live_runtime_from_source_text("physical-todomvc-toggle-all", &source_path, &source)
                .expect("physical TodoMVC runtime should initialize"),
        ));
        let state_summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(state_summary["store"]["active_count"], 3);
        assert_eq!(state_summary["store"]["completed_count"], 1);
        assert_eq!(state_summary["store"]["all_completed"], false);
        let (layout_proof, layout_frame) = native_document_layout_proof_with_state_embedded(
            &source_path,
            &source,
            Some(&state_summary),
        )
        .expect("physical TodoMVC layout should lower");
        let shared_render_state = Arc::new(Mutex::new(PreviewSharedRenderState {
            layout_proof,
            layout_frame_override: Some(Arc::new(layout_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        }));
        let mut input_state = PreviewNativeInputState::default();

        for (index, expected_completed, expected_active_count, expected_completed_count) in
            [(0_u64, true, 0_i64, 4_i64), (1_u64, false, 4_i64, 0_i64)]
        {
            let layout = shared_render_state.lock().unwrap().layout_proof.clone();
            let (toggle_x, toggle_y, _) =
                source_hit_center(&layout, "store.elements.toggle_all_checkbox")
                    .expect("physical toggle-all should expose a hit region");
            preview_apply_real_window_input(
                &deterministic_click_input_from_index(index, toggle_x, toggle_y),
                &source_path,
                &source,
                Some(&live_runtime),
                &shared_render_state,
                &mut input_state,
            )
            .expect("clicking physical toggle-all should dispatch a source event");
            let summary = live_runtime.lock().unwrap().document_state_summary();
            let todos = summary["todos"]
                .as_array()
                .expect("physical TodoMVC state should expose todos");
            assert!(
                todos
                    .iter()
                    .all(|todo| todo["completed"].as_bool() == Some(expected_completed)),
                "toggle-all click {index} should set every row to {expected_completed}: {todos:?}"
            );
            assert_eq!(
                summary["store"]["active_count"].as_i64(),
                Some(expected_active_count)
            );
            assert_eq!(
                summary["store"]["completed_count"].as_i64(),
                Some(expected_completed_count)
            );
            assert_eq!(
                summary["store"]["all_completed"].as_bool(),
                Some(expected_completed)
            );
            assert_physical_todomvc_preview_healthy(
                &shared_render_state,
                &format!("after toggle-all click {index}"),
            );
        }
    }

    #[test]
    fn physical_todomvc_empty_state_hides_toggle_all_and_bulk_footer_controls() {
        let source_path = repo_path("examples/todo_mvc_physical/RUN.bn");
        let source =
            std::fs::read_to_string(&source_path).expect("physical TodoMVC source should exist");
        let mut state = physical_todomvc_seed_state("Classic", "Light");
        state["store"]["todos"] = json!([]);
        state["store"]["active_count"] = json!(0);
        state["store"]["completed_count"] = json!(0);
        state["store"]["has_todos"] = json!(false);
        state["store"]["has_completed"] = json!(false);
        state["store"]["all_completed"] = json!(false);
        mirror_physical_todomvc_seed_root_fields(&mut state);
        let (layout_proof, layout) =
            native_document_layout_proof_with_state_embedded(&source_path, &source, Some(&state))
                .expect("empty physical TodoMVC layout should lower");
        assert!(
            source_hit_center(&layout_proof, "store.elements.toggle_all_checkbox").is_err(),
            "empty physical TodoMVC should not expose a toggle-all hit region"
        );
        assert!(
            !layout
                .display_list
                .iter()
                .any(|item| matches!(item.kind, boon_document_model::DocumentNodeKind::Checkbox)),
            "empty physical TodoMVC should not render row checkboxes"
        );
        assert!(
            !layout
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("Clear completed")),
            "empty physical TodoMVC should hide the clear-completed control"
        );
        assert!(
            physical_new_todo_input_item(&layout).is_some(),
            "empty physical TodoMVC should keep the new-todo input visible"
        );
    }

    #[test]
    fn physical_todomvc_theme_and_mode_clicks_restyle_preview() {
        let source_path = repo_path("examples/todo_mvc_physical/RUN.bn");
        let source =
            std::fs::read_to_string(&source_path).expect("physical TodoMVC source should exist");
        let live_runtime = Arc::new(Mutex::new(
            live_runtime_from_source_text("physical-todomvc-theme-clicks", &source_path, &source)
                .expect("physical TodoMVC runtime should initialize"),
        ));
        let state_summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(state_summary["theme_options"]["mode"], "Light");
        let (layout_proof, layout_frame) = native_document_layout_proof_with_state_embedded(
            &source_path,
            &source,
            Some(&state_summary),
        )
        .expect("physical TodoMVC layout should lower");
        let initial_root_color = frame_root_material_color(&layout_frame)
            .expect("initial physical frame should expose a root material color");
        let shared_render_state = Arc::new(Mutex::new(PreviewSharedRenderState {
            layout_proof,
            layout_frame_override: Some(Arc::new(layout_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        }));
        let mut input_state = PreviewNativeInputState::default();

        let initial_frame = latest_preview_frame(&shared_render_state);
        assert_physical_todomvc_frame_theme_styles(
            &initial_frame,
            "Classic",
            "Light",
            "initial Classic light frame",
        );
        let initial_new_todo_input = physical_new_todo_input_item(&initial_frame)
            .expect("initial physical frame should expose the new-todo text input");
        assert_eq!(
            initial_new_todo_input.style.get("placeholder_size"),
            Some(&boon_document_model::StyleValue::Number(24.0)),
            "Classic placeholder should lower its nested Theme/font(Placeholder) size"
        );
        let mut previous_checkbox_check_color =
            first_todo_checkbox_style_text(&initial_frame, "check_color")
                .expect("initial physical frame should expose themed checkbox check color");
        let mut previous_root_color = initial_root_color;

        let classic_light_mode_layout = shared_render_state.lock().unwrap().layout_proof.clone();
        let (classic_mode_x, classic_mode_y, _) = source_hit_center(
            &classic_light_mode_layout,
            "store.elements.theme_switcher.mode_toggle",
        )
        .expect("Classic mode toggle should have a hit region");
        preview_apply_real_window_input(
            &deterministic_click_input_from_index(1, classic_mode_x, classic_mode_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking Classic mode toggle should dispatch a source event");
        let classic_dark_summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(classic_dark_summary["theme_options"]["name"], "Classic");
        assert_eq!(classic_dark_summary["theme_options"]["mode"], "Dark");
        let classic_dark_frame = latest_preview_frame(&shared_render_state);
        assert_physical_todomvc_frame_theme_styles(
            &classic_dark_frame,
            "Classic",
            "Dark",
            "after toggling Classic dark mode",
        );
        assert!(
            classic_dark_frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("Light mode")),
            "Classic dark mode toggle label should update after switching to dark"
        );
        let classic_dark_root_color = frame_root_material_color(&classic_dark_frame)
            .expect("Classic dark frame should expose a root material color");
        assert_ne!(
            classic_dark_root_color, previous_root_color,
            "Classic dark should re-lower the viewport root material, not keep the light background"
        );
        let classic_dark_checkbox_check_color =
            first_todo_checkbox_style_text(&classic_dark_frame, "check_color")
                .expect("Classic dark frame should expose themed row checkbox check color");
        assert_ne!(
            classic_dark_checkbox_check_color, previous_checkbox_check_color,
            "Classic dark should re-lower todo row checkbox glyph colors"
        );
        assert_physical_todomvc_preview_healthy(
            &shared_render_state,
            "after toggling Classic dark mode",
        );

        let classic_dark_mode_layout = shared_render_state.lock().unwrap().layout_proof.clone();
        let (classic_light_x, classic_light_y, _) = source_hit_center(
            &classic_dark_mode_layout,
            "store.elements.theme_switcher.mode_toggle",
        )
        .expect("Classic mode toggle should still have a hit region");
        preview_apply_real_window_input(
            &deterministic_click_input_from_index(2, classic_light_x, classic_light_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking Classic mode toggle back to light should dispatch a source event");
        let classic_light_summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(classic_light_summary["theme_options"]["name"], "Classic");
        assert_eq!(classic_light_summary["theme_options"]["mode"], "Light");
        let classic_light_frame = latest_preview_frame(&shared_render_state);
        assert_physical_todomvc_frame_theme_styles(
            &classic_light_frame,
            "Classic",
            "Light",
            "after returning Classic light mode",
        );
        previous_root_color = frame_root_material_color(&classic_light_frame)
            .expect("Classic light frame should expose a root material color");
        previous_checkbox_check_color =
            first_todo_checkbox_style_text(&classic_light_frame, "check_color")
                .expect("Classic light frame should expose themed checkbox check color");

        let themes = [
            ("Classic", "classic"),
            ("Professional", "professional"),
            ("Glassmorphism", "glassmorphism"),
            ("Neobrutalism", "neobrutalism"),
            ("Neumorphism", "neumorphism"),
        ];
        for (index, (expected_name, source_suffix)) in themes.iter().enumerate() {
            let layout = shared_render_state.lock().unwrap().layout_proof.clone();
            let source_event = format!("store.elements.theme_switcher.{source_suffix}");
            let (x, y, _) = source_hit_center(&layout, &source_event).unwrap_or_else(|_| {
                panic!("{expected_name} theme button should have a hit region")
            });
            preview_apply_real_window_input(
                &deterministic_click_input_from_index(10 + index as u64, x, y),
                &source_path,
                &source,
                Some(&live_runtime),
                &shared_render_state,
                &mut input_state,
            )
            .unwrap_or_else(|_| panic!("clicking {expected_name} should dispatch a source event"));
            let summary = live_runtime.lock().unwrap().document_state_summary();
            assert_eq!(summary["theme_options"]["name"], *expected_name);
            assert_eq!(summary["theme_options"]["mode"], "Light");
            assert_physical_todomvc_preview_healthy(
                &shared_render_state,
                &format!("after clicking {expected_name} theme"),
            );
            let frame = latest_preview_frame(&shared_render_state);
            assert_physical_todomvc_frame_theme_styles(
                &frame,
                expected_name,
                "Light",
                &format!("after clicking {expected_name} theme"),
            );
            let root_color = frame_root_material_color(&frame).unwrap_or_else(|| {
                panic!("{expected_name} frame should expose a root material color")
            });
            let checkbox_check_color = first_todo_checkbox_style_text(&frame, "check_color")
                .unwrap_or_else(|| {
                    panic!("{expected_name} frame should expose themed row checkbox check color")
                });
            if *expected_name != "Classic" {
                assert_ne!(
                    root_color, previous_root_color,
                    "changing to {expected_name} should re-lower visible material colors"
                );
                assert_ne!(
                    checkbox_check_color, previous_checkbox_check_color,
                    "changing to {expected_name} should re-lower todo row checkbox glyph colors"
                );
            }
            if *expected_name == "Glassmorphism" {
                assert!(
                    root_color.contains("#eef7ff"),
                    "Glassmorphism should visibly switch to the glass palette, got {root_color}"
                );
            }
            if *expected_name == "Neobrutalism" {
                let new_todo_input = physical_new_todo_input_item(&frame)
                    .expect("Neobrutalism frame should expose the new-todo text input");
                assert_eq!(
                    new_todo_input.style.get("size"),
                    Some(&boon_document_model::StyleValue::Number(23.0)),
                    "typed input text should keep the Neobrutalism Input font size"
                );
                assert_eq!(
                    new_todo_input.style.get("placeholder_size"),
                    Some(&boon_document_model::StyleValue::Number(22.0)),
                    "placeholder text should use the Neobrutalism Placeholder font size"
                );
            }
            previous_root_color = root_color;
            previous_checkbox_check_color = checkbox_check_color;
        }

        let light_before_mode_root_color = previous_root_color;
        let light_before_mode_checkbox_check_color = previous_checkbox_check_color;
        let mode_layout = shared_render_state.lock().unwrap().layout_proof.clone();
        let (mode_x, mode_y, _) =
            source_hit_center(&mode_layout, "store.elements.theme_switcher.mode_toggle")
                .expect("mode toggle should have a hit region");
        preview_apply_real_window_input(
            &deterministic_click_input_from_index(20, mode_x, mode_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking mode toggle should dispatch a source event");
        let dark_summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(dark_summary["theme_options"]["name"], "Neumorphism");
        assert_eq!(dark_summary["theme_options"]["mode"], "Dark");
        let dark_frame = latest_preview_frame(&shared_render_state);
        assert_physical_todomvc_frame_theme_styles(
            &dark_frame,
            "Neumorphism",
            "Dark",
            "after toggling Neumorphism dark mode",
        );
        let dark_root_color = frame_root_material_color(&dark_frame)
            .expect("dark physical frame should expose a root material color");
        assert_ne!(
            dark_root_color, light_before_mode_root_color,
            "changing light/dark mode should re-lower visible material colors"
        );
        let dark_checkbox_check_color = first_todo_checkbox_style_text(&dark_frame, "check_color")
            .expect("dark frame should expose themed row checkbox check color");
        assert_ne!(
            dark_checkbox_check_color, light_before_mode_checkbox_check_color,
            "changing light/dark mode should re-lower todo row checkbox glyph colors"
        );
        assert!(
            !dark_frame
                .display_list
                .iter()
                .any(|item| item.style.contains_key("asset_url")),
            "themed physical rows should not keep stale SVG asset icons after mode changes"
        );
        assert!(
            dark_frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("Light mode")),
            "mode toggle label should update after switching to dark mode"
        );
        assert_physical_todomvc_preview_healthy(&shared_render_state, "after toggling dark mode");

        let themed_layout = shared_render_state.lock().unwrap().layout_proof.clone();
        let (input_x, input_y, input_node) =
            source_hit_center(&themed_layout, "store.elements.new_todo_title_text_input")
                .expect("new todo input should still have a hit region after theme changes");
        preview_apply_real_window_input(
            &deterministic_click_input_from_index(100, input_x, input_y),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("clicking the themed new todo input should focus it");
        assert_eq!(
            input_state.focused_node.as_deref(),
            Some(input_node.as_str())
        );

        let themed_title = "after theme switch";
        let themed_typed = test_keyboard_input(
            themed_title
                .chars()
                .enumerate()
                .map(|(index, character)| {
                    test_key_press(101_u64.saturating_add(index as u64), &character.to_string())
                })
                .collect(),
            Vec::new(),
        );
        preview_apply_real_window_input(
            &themed_typed,
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("typing a todo title should still work after theme changes");
        preview_apply_real_window_input(
            &test_keyboard_input(vec![test_key_press(140, "Return")], Vec::new()),
            &source_path,
            &source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .expect("pressing Enter should submit a themed todo");
        let themed_summary = live_runtime.lock().unwrap().document_state_summary();
        assert!(
            themed_summary["todos"]
                .as_array()
                .expect("physical TodoMVC todos should remain a list")
                .iter()
                .any(|todo| todo.get("title").and_then(serde_json::Value::as_str)
                    == Some(themed_title)),
            "add-todo should still work after clicking every theme and toggling mode"
        );
        assert_physical_todomvc_preview_healthy(
            &shared_render_state,
            "after add todo following theme changes",
        );
    }

    fn test_type_scalar(label: &str) -> TypeDisplayNode {
        TypeDisplayNode::Scalar {
            label: label.to_owned(),
        }
    }

    fn test_type_object(fields: Vec<(&str, TypeDisplayNode)>) -> TypeDisplayNode {
        TypeDisplayNode::Object {
            fields: fields
                .into_iter()
                .map(|(name, ty)| TypeDisplayField {
                    name: name.to_owned(),
                    ty,
                })
                .collect(),
            open: false,
        }
    }

    fn test_type_list(item: TypeDisplayNode) -> TypeDisplayNode {
        TypeDisplayNode::List {
            item: Box::new(item),
        }
    }

    fn test_type_union(labels: &[&str]) -> TypeDisplayNode {
        TypeDisplayNode::Union {
            variants: labels.iter().map(|label| test_type_scalar(label)).collect(),
        }
    }

    #[test]
    fn parser_backed_syntax_tokens_classify_comments_and_invalid_reserved_tokens() {
        let model = CodeEditorModel::new(
            "custom://syntax.bn",
            "-- comment\nEXAMPLE Demo\n# old comment\nSOURCE\nElement/label(label: TEXT { Hi })\ncount + 1\n",
        );

        assert_eq!(model.syntax_backend(), "boon_parser::parse_ast");
        assert!(model.syntax_parser_backed());
        let categories = model.syntax_categories();
        assert!(categories.contains(&"comment"));
        assert!(categories.contains(&"keyword"));
        assert!(categories.contains(&"source-binding"));
        assert!(categories.contains(&"operator"));
        assert!(categories.contains(&"invalid"));

        let invalid_texts = model
            .syntax_tokens
            .iter()
            .filter(|token| token.kind == "invalid")
            .map(|token| token.text.as_str())
            .collect::<Vec<_>>();
        assert!(invalid_texts.contains(&"EXAMPLE"));
        assert!(invalid_texts.contains(&"#"));
    }

    #[test]
    fn highlighted_line_segments_preserve_plain_gaps_and_token_kinds() {
        let model = CodeEditorModel::new("custom://line.bn", "count: SOURCE\ncount + 1\n");
        let segments = model.highlighted_line_segments(2, "count + 1");

        assert_eq!(
            segments
                .iter()
                .map(|segment| (segment.kind, segment.text.as_str()))
                .collect::<Vec<_>>(),
            vec![
                ("variable", "count"),
                ("plain", " "),
                ("operator", "+"),
                ("plain", " "),
                ("number", "1")
            ]
        );
    }

    #[test]
    fn highlighted_line_segments_keep_space_before_closing_punctuation() {
        let model = CodeEditorModel::new("custom://line.bn", "thing: [press: SOURCE ]\n");
        let segments = model.highlighted_line_segments(1, "thing: [press: SOURCE ]");
        let source_index = segments
            .iter()
            .position(|segment| segment.text == "SOURCE")
            .expect("SOURCE token should be highlighted");

        assert_eq!(segments[source_index].kind, "keyword");
        assert_eq!(segments[source_index + 1].text, " ");
        assert_eq!(segments[source_index + 2].text, "]");
    }

    #[test]
    fn code_editor_view_renders_mixed_lines_as_colored_segments() {
        let model = CodeEditorModel::new("custom://view.bn", "count: SOURCE\ncount + 1\n");
        let mut frame = boon_document_model::DocumentFrame::empty("root");
        let parent = frame.root.clone();
        CodeEditorView::new().append_to(&mut frame, parent, &model, 160, true);

        let code_row = frame
            .nodes
            .get(&boon_document_model::DocumentNodeId(
                "dev-code-editor-code-row-2".to_owned(),
            ))
            .expect("line 2 code row should render");
        assert_eq!(code_row.children.len(), 1);
        let rendered = frame
            .nodes
            .get(&code_row.children[0])
            .expect("line text should render as one rich text node");
        assert_eq!(
            rendered.text.as_ref().map(|text| text.text.as_str()),
            Some("count + 1")
        );
        assert_eq!(
            rendered.style.get("text_inset"),
            Some(&boon_document_model::StyleValue::Number(0.0))
        );
        assert_eq!(
            rendered.style.get("text_clip_padding"),
            Some(&boon_document_model::StyleValue::Number(0.0))
        );

        let spans = style_rich_text_spans_for_test(
            rendered
                .style
                .get("syntax_spans_json")
                .expect("rich syntax spans should be attached"),
        );
        assert_eq!(
            spans
                .iter()
                .map(|span| span.text.as_str())
                .collect::<Vec<_>>(),
            vec!["count", " ", "+", " ", "1"]
        );
        assert!(spans.iter().any(|span| {
            span.text == "+" && span.color.as_deref() == Some(syntax_color_for_kind("operator"))
        }));
        assert!(spans.iter().any(|span| {
            span.text == "1" && span.color.as_deref() == Some(syntax_color_for_kind("number"))
        }));
    }

    #[test]
    fn code_editor_view_preserves_pipe_forward_source_for_font_ligature_shaping() {
        let model = CodeEditorModel::new("custom://view.bn", "0 |> HOLD count\n");
        let mut frame = boon_document_model::DocumentFrame::empty("root");
        let parent = frame.root.clone();
        CodeEditorView::new().append_to(&mut frame, parent, &model, 80, true);
        let code_row = frame
            .nodes
            .get(&boon_document_model::DocumentNodeId(
                "dev-code-editor-code-row-1".to_owned(),
            ))
            .expect("line 1 code row should render");
        let rendered = frame
            .nodes
            .get(&code_row.children[0])
            .expect("line text should render");
        let spans = style_rich_text_spans_for_test(
            rendered
                .style
                .get("syntax_spans_json")
                .expect("rich syntax spans should be attached"),
        );
        assert_eq!(
            spans
                .iter()
                .map(|span| span.text.as_str())
                .collect::<Vec<_>>(),
            vec!["0", " ", "|>", " ", "HOLD", " ", "count"]
        );
        assert!(
            spans
                .iter()
                .any(|span| { span.source_text.as_deref() == Some("|>") && span.text == "|>" })
        );
    }

    #[test]
    fn code_editor_view_attaches_virtual_type_hint_metadata_without_changing_source_spans() {
        let source = include_str!("../../../examples/counter.bn").to_owned();
        let mut model = CodeEditorModel::new("examples/counter.bn", &source);
        assert_eq!(model.type_hint_backend(), "boon_typecheck::TypeHintTable");
        assert!(model.type_hint_count() > 0);
        let call_line = source
            .lines()
            .position(|line| line.trim() == "root: counter_app()")
            .map(|index| index + 1)
            .expect("counter source should contain a root function call");
        let call_line_source = model.line_text(call_line - 1);
        model.scroll_line = call_line.saturating_sub(1);

        let mut frame = boon_document_model::DocumentFrame::empty("root");
        let parent = frame.root.clone();
        CodeEditorView::new().append_to(&mut frame, parent, &model, 820, true);
        let rendered = frame
            .nodes
            .get(&boon_document_model::DocumentNodeId(format!(
                "dev-code-editor-line-text-{call_line}"
            )))
            .expect("line text should render");
        let spans = style_rich_text_spans_for_test(
            rendered
                .style
                .get("syntax_spans_json")
                .expect("rich syntax spans should be attached"),
        );
        let source_text = spans
            .iter()
            .map(|span| span.source_text.as_deref().unwrap_or_default())
            .collect::<String>();
        assert_eq!(source_text, call_line_source);

        let type_hints = style_editor_type_hints_for_test(
            rendered
                .style
                .get("editor_type_hints_json")
                .expect("type hint metadata should be attached separately"),
        );
        assert!(type_hints.iter().any(|hint| {
            hint.compact_label.starts_with("[kind:") || hint.detail_label.contains("kind:")
        }));
    }

    #[test]
    fn editor_copy_excludes_virtual_inline_type_hints() {
        let source = include_str!("../../../examples/counter.bn").to_owned();
        let mut model = CodeEditorModel::new("examples/counter.bn", &source);
        let call_line = source
            .lines()
            .position(|line| line.trim() == "root: counter_app()")
            .map(|index| index + 1)
            .expect("counter source should contain a root function call");
        let line_source = model.line_text(call_line - 1).to_owned();
        assert!(
            !model.inline_type_hints_for_line(call_line).is_empty(),
            "test line should carry virtual inline type hints"
        );
        model.set_selection(
            EditorPosition {
                line: call_line,
                column: 1,
            },
            EditorPosition {
                line: call_line,
                column: line_source.chars().count() + 1,
            },
        );

        let mut clipboard = TestClipboard::default();
        let result = model.copy_to_adapter(&mut clipboard);
        assert_eq!(result["status"], "pass");
        assert_eq!(clipboard.text, line_source);
        assert!(!clipboard.text.contains(": [kind:"));
    }

    #[test]
    fn type_inspector_syntax_spans_color_notation_without_changing_text() {
        let text = "    completed: BOOL = False, count: NUMBER = 12, title: TEXT = TEXT { Done }";
        let spans_json = type_inspector_syntax_spans_json(text);
        let spans = serde_json::from_str::<Vec<serde_json::Value>>(&spans_json)
            .expect("inspector spans should be valid JSON");
        let source_text = spans
            .iter()
            .map(|span| span["source_text"].as_str().unwrap_or_default())
            .collect::<String>();
        assert_eq!(source_text, text);
        assert!(spans.iter().any(|span| {
            span["source_text"].as_str() == Some("completed")
                && span["color"].as_str() == Some(syntax_color_for_kind("definition"))
        }));
        assert!(spans.iter().any(|span| {
            span["source_text"].as_str() == Some("BOOL")
                && span["color"].as_str() == Some(syntax_color_for_kind("type"))
        }));
        assert!(spans.iter().any(|span| {
            span["source_text"].as_str() == Some("12")
                && span["color"].as_str() == Some(syntax_color_for_kind("number"))
        }));
        assert!(spans.iter().any(|span| {
            span["source_text"].as_str() == Some("False")
                && span["color"].as_str() == Some(syntax_color_for_kind("tag"))
        }));

        let empty_segments = type_inspector_syntax_segments(DEV_TYPE_INSPECTOR_EMPTY_STATE_TEXT);
        assert!(
            empty_segments.iter().all(|span| span.kind == "variable"),
            "empty-state text should not be highlighted as tags or types: {empty_segments:?}"
        );

        let text_value = "edit_text: TEXT = TEXT { Read documentation255 }";
        let text_value_segments = type_inspector_syntax_segments(text_value);
        assert_eq!(
            text_value_segments
                .iter()
                .map(|segment| segment.text.as_str())
                .collect::<String>(),
            text_value
        );
        let content_segment = text_value_segments
            .iter()
            .find(|segment| segment.text.contains("Read documentation255"))
            .expect("TEXT value content should stay in one content segment");
        assert_eq!(content_segment.kind, "text-literal-content");
    }

