        assert_eq!(shell.type_inspector_scroll_line, 0);
        assert_eq!(shell.type_inspector_scroll_column, 3);
        assert_eq!(shell.workspace.selected_buffer.scroll_column, 0);

        let scrolled = shell.document_for_viewport(1180, 820);
