    #[test]
    fn dev_editor_and_inspector_rows_stay_inside_visible_panels() {
        let source = include_str!("../../../examples/todomvc.bn").to_owned();
        let store_line = source
            .lines()
            .position(|line| line.trim() == "store: [")
            .map(|index| index + 1)
            .expect("TodoMVC should declare store");
        let (mut shell, _input_state, _document, _layout) = test_dev_editor_context(&source);
        shell.hovered_editor_position = Some(EditorPosition {
            line: store_line,
            column: 2,
        });

        let document = shell.document_for_viewport(881, 825);
        let mut measurer = boon_native_gpu::GlyphonTextMeasurer::new();
        let layout = boon_document::layout(boon_document::LayoutInput {
            document: &document,
            viewport: boon_host::Viewport {
                surface: 1,
                width: 881.0,
                height: 825.0,
                scale: 1.0,
            },
            text: &mut measurer,
            capabilities: boon_document::RenderCapabilities::fake_portable(),
        });

        let editor_bounds = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-code-editor")
            .expect("editor should be laid out")
            .bounds;
        let detail_bounds = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-type-inspector-detail")
            .expect("type inspector detail should be laid out")
            .bounds;
        let footer_scroll_bounds = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-footer-scroll")
            .expect("footer scroll should be laid out")
            .bounds;

        for item in layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-code-editor-line-text-"))
        {
            assert!(
                item.bounds.x + item.bounds.width <= editor_bounds.x + editor_bounds.width + 0.5,
                "{} leaks past editor: {:?} editor={:?}",
                item.node.0,
                item.bounds,
                editor_bounds
            );
        }
        for item in layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-type-inspector-detail-row-"))
        {
            assert!(
                item.bounds.y + item.bounds.height <= detail_bounds.y + detail_bounds.height + 0.5,
                "{} leaks below inspector detail: {:?} detail={:?}",
                item.node.0,
                item.bounds,
                detail_bounds
            );
        }
        for item in layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-footer-row-"))
        {
            assert!(
                item.bounds.y + item.bounds.height
                    <= footer_scroll_bounds.y + footer_scroll_bounds.height + 0.5,
                "{} leaks below footer scroll: {:?} footer={:?}",
                item.node.0,
                item.bounds,
                footer_scroll_bounds
            );
        }
    }

    #[test]
    fn dev_example_and_file_tabs_wrap_inside_narrow_viewport() {
        let source = std::fs::read_to_string(repo_path("examples/novywave/RUN.bn"))
            .expect("NovyWave entry source should be readable");
        let shell = DevWindowShell::new(
            "examples/novywave/RUN.bn",
            &source,
            Some("novywave"),
            PreviewTransport::new(None),
        );
        let viewport_width = 420;
        let viewport_height = 825;
        let document = shell.document_for_viewport(viewport_width, viewport_height);
        let mut measurer = boon_native_gpu::GlyphonTextMeasurer::new();
        let layout = boon_document::layout(boon_document::LayoutInput {
            document: &document,
            viewport: boon_host::Viewport {
                surface: 1,
                width: viewport_width as f32,
                height: viewport_height as f32,
                scale: 1.0,
            },
            text: &mut measurer,
            capabilities: boon_document::RenderCapabilities::fake_portable(),
        });

        let header = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-header")
            .expect("workspace header panel should be laid out")
            .bounds;
        let header_rows = layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-header-row-"))
            .collect::<Vec<_>>();
        assert!(
            header_rows.len() > 1,
            "narrow dev viewport should wrap workspace header controls"
        );
        for node_id in [
            "dev-header-title",
            "dev-header-file",
            "dev-header-preview-status",
            "dev-header-dirty-status",
            "dev-header-example",
            "dev-custom-name-input",
        ] {
            let item = layout
                .display_list
                .iter()
                .find(|item| item.node.0 == node_id)
                .unwrap_or_else(|| panic!("{node_id} should be visible in workspace header"));
            assert!(
                item.bounds.x >= header.x - 0.5
                    && item.bounds.x + item.bounds.width <= header.x + header.width + 0.5
                    && item.bounds.y >= header.y - 0.5
                    && item.bounds.y + item.bounds.height <= header.y + header.height + 0.5,
                "{node_id} leaks outside wrapped workspace header: {:?} container={:?}",
                item.bounds,
                header
            );
        }

        let example_tabs = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-example-tabs")
            .expect("example tab bar should be laid out")
            .bounds;
        let example_rows = layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-example-tabs-row-"))
            .collect::<Vec<_>>();
        assert!(
            example_rows.len() > 1,
            "narrow dev viewport should wrap example tabs to multiple rows"
        );
        let new_example_tab = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-tab-new")
            .expect("new example tab should be reachable");
        assert!(
            new_example_tab.bounds.x + new_example_tab.bounds.width
                <= example_tabs.x + example_tabs.width + 0.5,
            "new example tab leaks past tab bar: {:?} container={:?}",
            new_example_tab.bounds,
            example_tabs
        );
        for item in layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-tab-"))
        {
            assert!(
                item.bounds.x >= example_tabs.x - 0.5
                    && item.bounds.x + item.bounds.width
                        <= example_tabs.x + example_tabs.width + 0.5
                    && item.bounds.y >= example_tabs.y - 0.5
                    && item.bounds.y + item.bounds.height
                        <= example_tabs.y + example_tabs.height + 0.5,
                "{} leaks outside wrapped example tab bar: {:?} container={:?}",
                item.node.0,
                item.bounds,
                example_tabs
            );
        }

        let file_tabs = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-project-file-tabs")
            .expect("NovyWave file tab bar should be laid out")
            .bounds;
        let file_rows = layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-project-file-tabs-row-"))
            .collect::<Vec<_>>();
        assert!(
            file_rows.len() > 1,
            "narrow dev viewport should wrap NovyWave file tabs to multiple rows"
        );
        for item in layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-project-file-"))
        {
            assert!(
                item.bounds.x >= file_tabs.x - 0.5
                    && item.bounds.x + item.bounds.width <= file_tabs.x + file_tabs.width + 0.5
                    && item.bounds.y >= file_tabs.y - 0.5
                    && item.bounds.y + item.bounds.height <= file_tabs.y + file_tabs.height + 0.5,
                "{} leaks outside wrapped file tab bar: {:?} container={:?}",
                item.node.0,
                item.bounds,
                file_tabs
            );
        }

        let toolbar = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-toolbar")
            .expect("workspace command toolbar should be laid out")
            .bounds;
        let toolbar_rows = layout
            .display_list
            .iter()
            .filter(|item| item.node.0.starts_with("dev-toolbar-row-"))
            .collect::<Vec<_>>();
        assert!(
            toolbar_rows.len() > 1,
            "narrow dev viewport should wrap workspace command/dialog controls"
        );
        for node_id in [
            "dev-command-run",
            "dev-command-format",
            "dev-command-reset",
            "dev-command-remove_custom",
        ] {
            let item = layout
                .display_list
                .iter()
                .find(|item| item.node.0 == node_id)
                .unwrap_or_else(|| panic!("{node_id} should be visible in command toolbar"));
            assert!(
                item.bounds.x >= toolbar.x - 0.5
                    && item.bounds.x + item.bounds.width <= toolbar.x + toolbar.width + 0.5
                    && item.bounds.y >= toolbar.y - 0.5
                    && item.bounds.y + item.bounds.height <= toolbar.y + toolbar.height + 0.5,
                "{node_id} leaks outside wrapped workspace toolbar: {:?} container={:?}",
                item.bounds,
                toolbar
            );
        }
    }

    #[test]
    fn editor_horizontal_scroll_updates_column_without_moving_lines() {
        let source = (0..24)
            .map(|index| {
                format!(
                    "line_{index}: TEXT {{ abcdefghijklmnopqrstuvwxyz_abcdefghijklmnopqrstuvwxyz }}\n"
                )
            })
            .collect::<String>();
        let (mut shell, mut input_state, document, layout) = test_dev_editor_context(&source);
        let editor_bounds = layout
            .display_list
            .iter()
            .find(|item| item.node.0 == "dev-code-editor")
            .expect("editor should be laid out")
            .bounds;

        let mut horizontal_scroll = test_keyboard_input(Vec::new(), Vec::new());
        horizontal_scroll.scroll_delta_x = 24.0;
        horizontal_scroll.mouse_scroll_event_count = 1;
        horizontal_scroll.mouse_window_pos =
            Some(boon_native_app_window::NativeMouseWindowPosition {
                x: f64::from(editor_bounds.x + editor_bounds.width * 0.5),
                y: f64::from(editor_bounds.y + editor_bounds.height * 0.5),
                window_width: 1180.0,
                window_height: 820.0,
            });

        assert!(dev_apply_real_window_input(
            &horizontal_scroll,
            &document,
            &layout,
            1180,
            820,
            &mut shell,
            &mut input_state
        ));
        assert_eq!(shell.workspace.selected_buffer.scroll_line, 0);
        assert_eq!(shell.workspace.selected_buffer.scroll_column, 3);

        let scrolled = shell.document_for_viewport(1180, 820);
        let row = scrolled
            .nodes
            .get(&boon_document_model::DocumentNodeId(
                "dev-code-editor-line-text-1".to_owned(),
            ))
            .expect("editor row should render");
        assert_eq!(
            row.style.get("text_inset"),
            Some(&boon_document_model::StyleValue::Number(-29.76))
        );
    }

