    #[test]
    fn prewarm_source_project_ack_is_deferred_and_background_marks_hash() {
        let source_path = repo_path("examples/counter.bn");
        let source = boon_runtime::source_text_for_path(&source_path).unwrap();
        let source_hash = boon_runtime::sha256_bytes(source.as_bytes());
        let state = Arc::new(Mutex::new(PreviewIpcState {
            source_path: source_path.clone(),
            source_text: source.clone(),
            runtime_units: project_units_for_source_text(&source_path, &source),
            source_bytes: source.len() as u64,
            source_sha256: source_hash.clone(),
            runtime_summary: json!({"status": "pass"}),
            shared_render_state: Arc::new(Mutex::new(PreviewSharedRenderState {
                layout_proof: json!({"status": "pass"}),
                layout_frame_override: None,
                update_count: 0,
                scroll_x_px: 0.0,
                scroll_y_px: 0.0,
                last_error: None,
                last_error_count: 0,
                status_overlay: None,
                last_dirty_reason: None,
            })),
            live_runtime: None,
            world_scene: None,
            world_editor_session: None,
            latest_accepted_command_id: 0,
            latest_accepted_source_revision: 0,
            replace_status_cache: json!({"kind": "replace-source-status", "status": "ready"}),
            prewarmed_project_hashes: BTreeSet::new(),
            prewarmed_project_results: BTreeMap::new(),
            prewarm_worker: PreviewPrewarmWorkerQueue::default(),
            replace_worker: PreviewReplaceWorkerQueue::default(),
            ipc_counters: PreviewIpcCounterState::default(),
            shutdown: PreviewShutdownState::default(),
        }));
        let payload = SourceProjectPayload::single_unit(
            21,
            8,
            "opaque-counter-prewarm",
            "memory://counter-prewarm.bn",
            &source,
        );
        let response = preview_prewarm_source_project(
            &state,
            &json!({
                "kind": "prewarm-source-project",
                "payload": payload.clone()
            }),
        )
        .unwrap();

        assert_eq!(response["kind"], "prewarm-source-project-result");
        assert_eq!(response["status"], "queued", "{response}");
        assert_eq!(response["source_project_committed"], false);
        assert_eq!(response["source_project_prewarm_deferred"], true);
        assert_eq!(
            response["parse_lower_runtime_layout_timings"]["runtime_deferred"],
            true
        );
        assert!(response.get("document_layout_proof").is_none());
        assert!(response.get("preview_runtime_summary").is_none());

        let started = Instant::now();
        loop {
            let state_guard = state.lock().unwrap();
            let prewarmed = state_guard
                .prewarmed_project_hashes
                .contains(&payload.project_hash)
                && state_guard
                    .prewarmed_project_results
                    .contains_key(&payload.project_hash);
            drop(state_guard);
            if prewarmed {
                break;
            }
            assert!(
                started.elapsed() < Duration::from_secs(5),
                "background prewarm did not cache the built project"
            );
            std::thread::sleep(Duration::from_millis(10));
        }
        let ack = preview_enqueue_source_project(
            &state,
            &json!({
                "kind": "replace-source",
                "payload": payload.clone()
            }),
            boon_native_app_window::NativeWakeHandle::new(),
        )
        .unwrap();
        assert_eq!(ack["kind"], "replace-source-queued");
        assert_eq!(ack["status"], "queued");
        assert_eq!(ack["source_project_prewarmed"], true);
        assert_eq!(ack["source_project_committed_from_prewarm"], true);
        assert_eq!(ack["replace_job_queue_depth"], 0);
        let state = state.lock().unwrap();
        assert_eq!(state.replace_status_cache["status"], "pass");
        assert_eq!(state.replace_status_cache["command_id"], 21);
        assert_eq!(state.replace_status_cache["source_revision"], 8);
        assert!(
            !state
                .prewarmed_project_results
                .contains_key(&payload.project_hash),
            "replace-source should consume the cached prewarm result"
        );
    }

    #[test]
    fn switching_to_cells_builds_runtime_state_before_preview_commit() {
        let cells_path = repo_path("examples/cells.bn");
        let cells_source = boon_runtime::source_text_for_path(&cells_path).unwrap();
        let cells_units = boon_runtime::source_units_for_path(&cells_path).unwrap();
        assert_eq!(cells_units.len(), 8);
        assert!(!cells_source.contains("-- file:"));
        assert!(cells_source.contains("root: cells_app()"));
        assert!(cells_units.iter().any(|unit| {
            unit.path.ends_with("examples/cells/cell.bn")
                && unit.source.contains("FUNCTION new_cell")
        }));
        assert!(cells_units.iter().any(|unit| {
            unit.path.ends_with("examples/cells/view.bn")
                && unit.source.contains("FUNCTION cells_app")
        }));

        let payload = SourceProjectPayload::from_units(
            17,
            4,
            "opaque-cells-source-id",
            &cells_path.display().to_string(),
            cells_units
                .iter()
                .map(|unit| (unit.path.clone(), unit.source.clone()))
                .collect(),
        )
        .unwrap();
        let result = preview_build_source_project(payload, || true);

        assert_eq!(result.status, "pass");
        assert_eq!(result.runtime_summary["status"], "pass");
        assert_eq!(result.runtime_summary["owns_live_runtime"], true);
        assert!(
            result
                .runtime_summary
                .get("state_summary_top_level_keys")
                .and_then(serde_json::Value::as_array)
                .is_some_and(|keys| keys.iter().any(|key| key.as_str() == Some("cells"))),
            "Cells preview switch must build the real runtime state before committing"
        );
        assert!(result.live_runtime.is_some());
        assert_eq!(result.layout_proof["status"], "pass");
        assert_eq!(result.layout_proof["runtime_document_state_used"], true);
        assert_eq!(result.timings["runtime_deferred"], false);
        assert_eq!(result.timings["source_unit_count"], 8);
    }

