    #[test]
    fn counter_button_event_group_argument_lowers_press_source_intent() {
        let source_path = repo_path("examples/counter.bn");
        let source = boon_runtime::source_text_for_path(&source_path).unwrap();
        let units = vec![boon_runtime::RuntimeSourceUnit {
            path: source_path.display().to_string(),
            source: source.clone(),
        }];
        let runtime_analysis = boon_runtime::cached_runtime_static_analysis_from_project(
            "test-counter-bindings",
            &units,
        )
        .unwrap();
        let actual_source_binding_index =
            source_binding_index_from_view_bindings(&runtime_analysis.view_bindings);
        assert!(
            actual_source_binding_index
                .get(&("Button".to_owned(), "press".to_owned()))
                .is_some_and(|paths| paths
                    .iter()
                    .any(|path| path == "store.sources.increment_button.press")),
            "counter runtime static analysis should expose Button/press bindings, got index={actual_source_binding_index:?}, bindings={:?}",
            runtime_analysis.view_bindings
        );
        let parsed = boon_parser::parse_source(source_path.display().to_string(), source).unwrap();
        let functions =
            DocumentFunctionRegistry::new(&parsed.ast.statements, &parsed.ast.expressions);
        let counter_button = functions.get("counter_button").unwrap();
        let increment_button = functions.get("increment_button").unwrap();
        let call = increment_button
            .children
            .iter()
            .find(|statement| {
                document_call_function(statement, &parsed.ast.expressions) == Some("counter_button")
            })
            .expect("increment_button should call counter_button");
        let context = DocumentEvalContext {
            root: None,
            locals: DocumentScopedMap::new(),
            local_origins: DocumentScopedMap::new(),
            render_args: DocumentScopedMap::new(),
            passed: None,
            source_binding_index: Arc::new(actual_source_binding_index),
            runtime_source_paths: Arc::new(BTreeSet::new()),
            source_address_lookup_fields: Arc::new(BTreeMap::new()),
            runtime_row_scope_by_list: Arc::new(BTreeMap::new()),
            data_binding_index: Arc::new(BTreeMap::new()),
            data_reads: Arc::new(Mutex::new(BTreeSet::new())),
            data_binding_targets: Arc::new(Mutex::new(BTreeMap::new())),
            structural_data_reads: Arc::new(Mutex::new(BTreeSet::new())),
            source_override: None,
            functions: Some(&functions),
            eval_depth: 0,
            eval_cache: Arc::new(Mutex::new(BTreeMap::new())),
        };
        let scoped =
            document_function_call_context(counter_button, call, &parsed.ast.expressions, &context);
        let button_statement = counter_button
            .children
            .iter()
            .find(|statement| {
                canonical_element_function(statement, &parsed.ast.expressions)
                    == Some("Element/button")
            })
            .expect("counter_button should lower through Element/button");
        let mut node = boon_document_model::DocumentNode::new(
            "counter-button-test",
            boon_document_model::DocumentNodeKind::Button,
        );
        let node_id = node.id.clone();
        let mut source_intents = Vec::new();
        let typecheck_report = boon_typecheck::check(&parsed);
        lower_canonical_element_sources(
            button_statement,
            &parsed.ast.expressions,
            &scoped,
            &typecheck_report,
            &node_id,
            &mut node,
            &mut source_intents,
        );
        assert!(
            source_intents.iter().any(|intent| {
                source_intent_kind_routes_event(
                    intent.get("intent").and_then(serde_json::Value::as_str),
                ) && intent
                    .get("source_path")
                    .and_then(serde_json::Value::as_str)
                    == Some("store.sources.increment_button.press")
            }),
            "counter_button event-group argument should lower a press intent, got {source_intents:?}; scoped origins={:?}",
            scoped.local_origins
        );
    }

    #[test]
    fn counter_button_source_intents_include_visible_targets() {
        let source_path = repo_path("examples/counter.bn");
        let source = boon_runtime::source_text_for_path(&source_path).unwrap();
        let proof = native_document_layout_proof(&source_path, &source).unwrap();
        let intents = proof["source_intent_assertions"].as_array().unwrap();

        for (source_path, target_text) in [
            ("store.sources.increment_button.press", "+"),
            ("store.sources.decrement_button.press", "-"),
            ("store.sources.reset_button.press", "Reset"),
        ] {
            let node = intents
                .iter()
                .find_map(|intent| {
                    (source_intent_kind_routes_event(
                        intent.get("intent").and_then(serde_json::Value::as_str),
                    ) && intent
                        .get("source_path")
                        .and_then(serde_json::Value::as_str)
                        == Some(source_path))
                    .then(|| intent.get("node").and_then(serde_json::Value::as_str))
                    .flatten()
                })
                .unwrap_or_else(|| panic!("{source_path} should expose a press intent"));
            assert!(
                intents.iter().any(|intent| {
                    intent.get("node").and_then(serde_json::Value::as_str) == Some(node)
                        && intent.get("intent").and_then(serde_json::Value::as_str)
                            == Some("target")
                        && intent
                            .get("source_path")
                            .and_then(serde_json::Value::as_str)
                            == Some(target_text)
                }),
                "{source_path} node {node} should expose target text {target_text:?}"
            );
        }
    }

    #[test]
    fn counter_operator_host_press_rebuilds_visible_count_layout() {
        let source_path = repo_path("examples/counter.bn");
        let source = boon_runtime::source_text_for_path(&source_path).unwrap();
        let source_hash = boon_runtime::sha256_bytes(source.as_bytes());
        let units = project_units_for_source_text(&source_path, &source);
        let mut runtime =
            boon_runtime::LiveRuntime::from_project("test-counter-operator-host-press", &units)
                .expect("counter runtime should initialize");
        let state_summary = runtime.document_state_summary();
        let (layout_proof, layout_frame) =
            native_document_layout_proof_with_project_state_embedded_for_viewport(
                &source_path,
                &units,
                Some(&state_summary),
                None,
            )
            .expect("counter initial layout should lower");
        assert!(
            layout_frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("0")),
            "initial counter frame should display 0"
        );
        let mut direct_runtime =
            boon_runtime::LiveRuntime::from_project("test-counter-direct-layout", &units)
                .expect("counter direct runtime should initialize");
        let direct_output = direct_runtime
            .apply_source_event_for_document_window(
                boon_runtime::LiveSourceEvent {
                    source: "store.sources.decrement_button.press".to_owned(),
                    text: None,
                    key: None,
                    list_id: None,
                    address: Some("-".to_owned()),
                    payload: BTreeMap::new(),
                    payload_bytes: BTreeMap::new(),
                    pointer_x: None,
                    pointer_y: None,
                    pointer_width: None,
                    pointer_height: None,
                    target_text: Some("-".to_owned()),
                    target_occurrence: None,
                    target_key: None,
                    target_generation: None,
                    bind_epoch: None,
                    source_epoch: None,
                    source_id: None,
                },
                0,
                16,
                0,
                16,
            )
            .expect("counter direct decrement should apply");
        assert_eq!(direct_output.state_summary.get("count"), Some(&json!(-1)));
        let direct_full_summary = direct_runtime.document_state_summary();
        assert_eq!(
            direct_full_summary.get("count"),
            Some(&json!(-1)),
            "fresh full document summary after decrement should keep count=-1: {}",
            serde_json::to_string(&direct_full_summary).unwrap()
        );
        let (_, direct_post_frame) =
            native_document_layout_proof_with_project_state_embedded_for_viewport(
                &source_path,
                &units,
                Some(&direct_output.state_summary),
                None,
            )
            .expect("counter direct post-input layout should lower");
        assert!(
            direct_post_frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("-1")),
            "direct post-input counter frame should display -1, state={}, texts={:?}",
            serde_json::to_string(&direct_output.state_summary).unwrap(),
            direct_post_frame
                .display_list
                .iter()
                .filter_map(|item| item.text.as_deref())
                .collect::<Vec<_>>()
        );
        let shared_render_state = Arc::new(Mutex::new(PreviewSharedRenderState {
            layout_proof,
            layout_frame_override: Some(Arc::new(layout_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        }));
        let state = PreviewIpcState {
            source_path: source_path.clone(),
            source_text: source.clone(),
            runtime_units: units,
            source_bytes: source.len() as u64,
            source_sha256: source_hash.clone(),
            runtime_summary: preview_runtime_summary(&source_path, &source, &source_hash),
            shared_render_state: Arc::clone(&shared_render_state),
            live_runtime: Some(Arc::new(Mutex::new(runtime))),
            world_scene: None,
            world_editor_session: None,
            latest_accepted_command_id: 0,
            latest_accepted_source_revision: 0,
            replace_status_cache: json!({"kind": "replace-source-status", "status": "ready"}),
            prewarmed_project_hashes: BTreeSet::new(),
            prewarmed_project_results: BTreeMap::new(),
            prewarm_worker: PreviewPrewarmWorkerQueue::default(),
            replace_worker: PreviewReplaceWorkerQueue::default(),
            ipc_counters: PreviewIpcCounterState::default(),
            shutdown: PreviewShutdownState::default(),
        };
        let decrement_source_event = operator_host_input_probe_requests(&source_path, &source)
            .expect("counter should produce operator host input probes")
            .into_iter()
            .find_map(|request| {
                request
                    .get("source_events")
                    .and_then(serde_json::Value::as_array)
                    .into_iter()
                    .flatten()
                    .find(|event| {
                        event
                            .get("source_event")
                            .and_then(|event| event.get("source"))
                            .and_then(serde_json::Value::as_str)
                            == Some("store.sources.decrement_button.press")
                    })
                    .cloned()
            })
            .expect("counter scenario should include decrement press");
        let request = json!({
            "kind": "operator-host-input",
            "source_path": source_path.display().to_string(),
            "source_hash": source_hash,
            "operator_host_input": true,
            "real_os_input": false,
            "source_events": [decrement_source_event],
            "preview_bound_scenario_data": false
        });

        let response = preview_operator_host_input_response(&state, &request).unwrap();

        assert_eq!(response["status"], "pass", "{response}");
        let outputs = response["outputs"]
            .as_array()
            .expect("operator-host response should expose outputs");
        let decrement_output = outputs
            .iter()
            .find(|output| {
                output
                    .get("event")
                    .and_then(|event| event.get("source"))
                    .and_then(serde_json::Value::as_str)
                    == Some("store.sources.decrement_button.press")
            })
            .expect("decrement output should be present");
        assert_eq!(
            decrement_output["framebuffer_delta_evidence"]["post_input_frame_method"],
            json!("render-patch-state-delta-and-paint-space-patch"),
            "button press must update visible runtime-backed layout instead of taking the focus-only overlay path: {decrement_output}"
        );
        assert_eq!(
            decrement_output["framebuffer_delta_evidence"]["post_input_layout_profile"]["render_scene_patch_layout_reuse"],
            json!(true),
            "fixed-box counter text should reuse retained layout with a render-scene sidecar: {decrement_output}"
        );
        let shared = shared_render_state
            .lock()
            .expect("shared render state should lock after decrement");
        let post_input_frame = shared
            .layout_frame_override
            .as_ref()
            .expect("post-input frame should be materialized");
        assert!(
            post_input_frame
                .display_list
                .iter()
                .any(|item| item.text.as_deref() == Some("0")),
            "retained counter layout should keep the stable text box while the render-scene patch carries -1"
        );
        let next_hash = shared
            .layout_proof
            .get("layout_frame_hash")
            .and_then(serde_json::Value::as_str)
            .expect("post-input layout proof should expose a layout hash");
        let render_scene_patch =
            cached_render_scene_patch(next_hash).expect("counter text sidecar should be cached");
        assert!(
            render_scene_patch
                .operations
                .iter()
                .any(|operation| matches!(
                    operation,
                    boon_document::RenderScenePatchOperation::TextContent { text, .. }
                        if text == "-1"
                )),
            "post-input counter render-scene patch should display -1: {:?}",
            render_scene_patch
        );
    }

