    fn average_image_luma(image: &image::RgbaImage, rect: boon_document::Rect) -> f32 {
        let x0 = rect.x.max(0.0).floor() as u32;
        let y0 = rect.y.max(0.0).floor() as u32;
        let x1 = (rect.x + rect.width).min(image.width() as f32).ceil() as u32;
        let y1 = (rect.y + rect.height).min(image.height() as f32).ceil() as u32;
        let mut total = 0.0;
        let mut count = 0.0_f32;
        for y in y0..y1 {
            for x in x0..x1 {
                total += image_luma_at(image, x as f32, y as f32);
                count += 1.0;
            }
        }
        total / count.max(1.0)
    }

    fn image_luma_range(image: &image::RgbaImage, rect: boon_document::Rect) -> f32 {
        let x0 = rect.x.max(0.0).floor() as u32;
        let y0 = rect.y.max(0.0).floor() as u32;
        let x1 = (rect.x + rect.width).min(image.width() as f32).ceil() as u32;
        let y1 = (rect.y + rect.height).min(image.height() as f32).ceil() as u32;
        let mut min_luma = f32::MAX;
        let mut max_luma = f32::MIN;
        for y in y0..y1 {
            for x in x0..x1 {
                let luma = image_luma_at(image, x as f32, y as f32);
                min_luma = min_luma.min(luma);
                max_luma = max_luma.max(luma);
            }
        }
        max_luma - min_luma
    }

    fn assert_rendered_text_region_has_luma_contrast(
        image: &image::RgbaImage,
        rect: boon_document::Rect,
        min_luma_range: f32,
        context: &str,
    ) -> f32 {
        let luma_range = image_luma_range(image, rect);
        assert!(
            luma_range >= min_luma_range,
            "{context} should have readable foreground/background luma contrast: range={luma_range:.2}, required={min_luma_range:.2}, bounds={rect:?}"
        );
        luma_range
    }

    fn rect_metric_json(rect: boon_document::Rect) -> serde_json::Value {
        json!({
            "x": rect.x,
            "y": rect.y,
            "width": rect.width,
            "height": rect.height
        })
    }

    fn image_abs_diff_sum(
        before: &image::RgbaImage,
        after: &image::RgbaImage,
        rect: boon_document::Rect,
    ) -> u64 {
        let x0 = rect.x.max(0.0).floor() as u32;
        let y0 = rect.y.max(0.0).floor() as u32;
        let x1 = (rect.x + rect.width).min(before.width() as f32).ceil() as u32;
        let y1 = (rect.y + rect.height).min(before.height() as f32).ceil() as u32;
        let mut total = 0_u64;
        for y in y0..y1 {
            for x in x0..x1 {
                let a = before.get_pixel(x, y);
                let b = after.get_pixel(x, y);
                total += (i16::from(a[0]) - i16::from(b[0])).unsigned_abs() as u64;
                total += (i16::from(a[1]) - i16::from(b[1])).unsigned_abs() as u64;
                total += (i16::from(a[2]) - i16::from(b[2])).unsigned_abs() as u64;
            }
        }
        total
    }

    fn cells_live_runtime(
        label: &str,
        cells_path: &Path,
        cells_source: &str,
    ) -> Arc<Mutex<boon_runtime::LiveRuntime>> {
        Arc::new(Mutex::new(
            live_runtime_from_source_text(label, cells_path, cells_source).unwrap(),
        ))
    }

    fn cells_live_runtime_with_scenario(
        label: &str,
        cells_path: &Path,
        cells_source: &str,
        scenario_path: &Path,
    ) -> boon_runtime::LiveRuntime {
        live_runtime_from_source_text_with_scenario(label, cells_path, cells_source, scenario_path)
            .unwrap()
    }

    fn test_key_press(
        sequence: u64,
        key: &str,
    ) -> boon_native_app_window::NativeKeyboardEventProof {
        boon_native_app_window::NativeKeyboardEventProof {
            sequence,
            key: key.to_owned(),
            pressed: true,
            window_protocol_id: Some(1),
        }
    }

    #[test]
    fn cells_scroll_materializes_later_window_and_can_return_to_origin() {
        let cells_path = repo_path("examples/cells.bn");
        let cells_source = boon_runtime::source_text_for_path(&cells_path).unwrap();
        let live_runtime =
            cells_live_runtime("native-cells-scroll-window", &cells_path, &cells_source);
        let (initial_layout, _) =
            preview_layout_for_scroll_window(&cells_path, &cells_source, &live_runtime, 0.0, 0.0)
                .unwrap();

        assert!(layout_has_visible_address(&initial_layout, "A0"));
        assert!(
            layout_has_visible_address(&initial_layout, "A20"),
            "initial Cells viewport should materialize the rows that fit in the visible sheet area"
        );
        assert!(
            !layout_has_visible_address(&initial_layout, "Z40"),
            "Z40 should require a scrolled Cells document window, not the initial frame"
        );

        let (scrolled_layout, _) = preview_layout_for_scroll_window(
            &cells_path,
            &cells_source,
            &live_runtime,
            25.0 * PREVIEW_TABLE_COLUMN_WIDTH_PX,
            40.0 * PREVIEW_TABLE_ROW_HEIGHT_PX,
        )
        .unwrap();
        assert!(
            layout_has_visible_address(&scrolled_layout, "Z40"),
            "scrolling down/right should materialize a real Z40 hit target"
        );

        let (returned_layout, _) =
            preview_layout_for_scroll_window(&cells_path, &cells_source, &live_runtime, 0.0, 0.0)
                .unwrap();
        assert!(
            layout_has_visible_address(&returned_layout, "A0"),
            "scrolling back to origin should restore a real A0 hit target"
        );
        assert!(
            !layout_has_visible_address(&returned_layout, "Z40"),
            "origin should not keep stale far-window cell hit targets"
        );
    }

