    #[test]
    fn cells_formula_bar_click_accepts_text_edit() {
        let cells_path = repo_path("examples/cells.bn");
        let cells_source = boon_runtime::source_text_for_path(&cells_path).unwrap();
        let live_runtime =
            cells_live_runtime("native-cells-formula-bar-edit", &cells_path, &cells_source);
        let (initial_layout, initial_frame) =
            preview_layout_for_scroll_window(&cells_path, &cells_source, &live_runtime, 0.0, 0.0)
                .unwrap();
        let (x, y, formula_node) = formula_bar_input_center(&initial_layout);
        assert_eq!(
            live_source_for_node_intent(&initial_layout, &formula_node, "click").as_deref(),
            None,
            "formula-bar focus is owned by the native text-input hit path"
        );
        assert!(
            !preview_text_input_live_change_enabled(&initial_layout, &formula_node),
            "formula-bar edits should defer runtime change events until commit"
        );
        assert_eq!(
            live_source_for_node_intent(&initial_layout, &formula_node, "change").as_deref(),
            Some("cell.sources.editor.change"),
            "selected formula bar change source should resolve through the runtime SourceBinding"
        );
        assert_eq!(
            live_source_for_node_intent(&initial_layout, &formula_node, "key_down").as_deref(),
            Some("cell.sources.editor.commit"),
            "selected formula bar key source should resolve through the runtime SourceBinding"
        );
        assert_eq!(
            live_source_for_node_intent(&initial_layout, &formula_node, "escape").as_deref(),
            Some("cell.sources.editor.cancel"),
            "selected formula bar escape source should resolve through the runtime SourceBinding"
        );
        assert_eq!(
            live_source_for_node_intent(&initial_layout, &formula_node, "blur").as_deref(),
            Some("cell.sources.editor.blur"),
            "selected formula bar blur source should resolve through the runtime SourceBinding"
        );
        assert_eq!(
            focused_address(&initial_layout, &formula_node).as_deref(),
            Some("A0"),
            "selected formula bar source events should keep the selected cell address"
        );
        let payload_summary = {
            let mut runtime = live_runtime.lock().unwrap();
            preview_payload_state_summary(&mut runtime)
        };
        assert_eq!(
            state_summary_value_for_data_path(&payload_summary, "store.selected_input.address")
                .and_then(serde_json::Value::as_str),
            Some("A0"),
            "payload summary should resolve selected_input address for native event dispatch"
        );
        assert_eq!(
            resolve_source_intent_payload_value_from_summary(
                &payload_summary,
                "store.selected_input.address".to_owned()
            ),
            "A0",
            "source-intent payload resolver should not leave selected_input address as a raw path"
        );
        let mut initial_change_event = boon_runtime::LiveSourceEvent {
            source: "cell.sources.editor.change".to_owned(),
            ..boon_runtime::LiveSourceEvent::default()
        };
        apply_layout_row_identity_to_event(
            &initial_layout,
            &formula_node,
            None,
            &mut initial_change_event,
        );
        assert!(
            initial_change_event.target_key.is_some(),
            "formula-bar change source should carry selected row identity before dispatch: {}",
            serde_json::to_string(&live_source_event_report(&initial_change_event)).unwrap()
        );
        let shared_render_state = Arc::new(Mutex::new(PreviewSharedRenderState {
            layout_proof: initial_layout,
            layout_frame_override: Some(Arc::new(initial_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        }));
        let mut input_state = PreviewNativeInputState::default();

        let click = deterministic_click_input_from_index(0, x, y);
        preview_apply_real_window_input(
            &click,
            &cells_path,
            &cells_source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .unwrap();
        let keys = test_keyboard_input(
            vec![
                test_key_press(1, "Backspace"),
                test_key_press(2, "Num4"),
                test_key_press(3, "Num2"),
            ],
            Vec::new(),
        );
        preview_apply_real_window_input(
            &keys,
            &cells_path,
            &cells_source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .unwrap();

        let summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(summary["store"]["selected_address"], "A0");
        assert_ne!(
            summary["store"]["selected_input"]["editing_text"], "42",
            "formula-bar keystrokes should stay in the retained native draft until commit"
        );
        assert_eq!(input_state.focused_text, "42");
        let shared = shared_render_state.lock().unwrap();
        let formula_item = shared
            .layout_frame_override
            .as_ref()
            .unwrap()
            .display_list
            .iter()
            .find(|item| item.node.0 == formula_node)
            .expect("formula bar should remain in the frame");
        assert!(formula_item.focused);
        assert_eq!(formula_item.text.as_deref(), Some("42"));
        assert_eq!(
            formula_item
                .style
                .get("caret_column")
                .and_then(|value| match value {
                    boon_document_model::StyleValue::Number(value) => Some(*value),
                    _ => None,
                }),
            Some(2.0)
        );

        let enter = test_keyboard_input(vec![test_key_press(4, "Return")], Vec::new());
        drop(shared);
        preview_apply_real_window_input(
            &enter,
            &cells_path,
            &cells_source,
            Some(&live_runtime),
            &shared_render_state,
            &mut input_state,
        )
        .unwrap();
        let summary = live_runtime.lock().unwrap().document_state_summary();
        assert_eq!(summary["store"]["selected_input"]["formula_text"], "42");
        assert_eq!(summary["store"]["selected_input"]["value"], "42");
        assert_eq!(summary["store"]["selected_input"]["editing"], false);
        assert!(
            input_state.focused_node.is_none(),
            "Enter should commit and blur the focused cell editor"
        );
        let frame = latest_preview_frame(&shared_render_state);
        assert_eq!(
            frame_caret_column_for_node(&frame, &formula_node),
            None,
            "committed formula bar should not keep a focused caret after Enter"
        );
    }

    #[test]
    fn preview_route_cache_key_uses_snapshot_key_with_embedded_source_intents() {
        let source_path = repo_path("examples/counter.bn");
        let source = boon_runtime::source_text_for_path(&source_path).unwrap();
        let mut layout_proof = native_document_layout_proof(&source_path, &source).unwrap();
        let layout_hash = layout_proof
            .get("layout_frame_hash")
            .and_then(serde_json::Value::as_str)
            .expect("counter layout proof should have a cached layout hash");
        let snapshot = cached_document_render_snapshot(layout_hash)
            .expect("counter layout proof should cache the document render snapshot");
        assert!(
            snapshot.hit_route_static_cache_key.is_some(),
            "render snapshots should retain a precomputed route key"
        );
        assert!(
            !snapshot.source_intents.is_empty(),
            "counter layout should have source intents for route-key coverage"
        );
        layout_proof["source_intent_assertions"] = json!(snapshot.source_intents.clone());
        let shared = PreviewSharedRenderState {
            layout_proof,
            layout_frame_override: Some(Arc::clone(&snapshot.layout_frame)),
            update_count: 0,
            scroll_x_px: 0.0,
            scroll_y_px: 0.0,
            last_error: None,
            last_error_count: 0,
            status_overlay: None,
            last_dirty_reason: None,
        };
        let source_intents = shared
            .layout_proof
            .get("source_intent_assertions")
            .and_then(serde_json::Value::as_array)
            .expect("synthetic embedded proof should expose source intents");

        assert_eq!(
            preview_hit_route_cache_key(
                &shared,
                snapshot.as_ref(),
                shared.layout_frame_override.as_deref().unwrap(),
                source_intents,
            ),
            snapshot.hit_route_static_cache_key.clone(),
            "embedded source intents must not force per-click route fingerprinting when the snapshot has a valid route key"
        );
    }

